EY1w6zbHQ_GKtLm0eCxZNfhcChyhL3FtOHIsdt-iqp5FYkrMDVtfDh2D77pM_b1r8rAu2hsgdJDYc6Mxo2b6T5NXD_9tiKQ8s9x0hHtyJWj6THju-QceM3OfxlnKQykHRQdwofGlLlkqTqidVoUxkgbZEqbcG6dCpO-7_fGWwiooC4Pyg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Entrée gratuite le premier samedi du mois de 17h à 21h. Architecture sublime.","specials":{"cuisine":[],"drinks":[]}}', 'Le nouveau phare de l''art contemporain à Paris. L''homme d''affaires François Pinault a installé sa collection dans l''ancienne Bourse de Commerce, restaurée et transformée par Tadao Ando avec un cylindre de béton minimaliste magistral au centre de la rotonde. La fresque de la coupole a été restaurée, le contraste ancien/moderne est saisissant. C''est un lieu d''art vivant, parfois déroutant (pigeons empaillés, cire qui fond), à l''architecture époustouflante.', 'Entrée gratuite le premier samedi du mois de 17h à 21h. Architecture sublime.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-061', 'Bourse de Commerce - Pinault Collection', 'museum', 'musee', '2 Rue de Viarmes', '', 'Le nouveau phare de l''art contemporain à Paris. L''homme d''affaires François Pinault a installé sa collection dans l''ancienne Bourse de Commerce, restaurée et transformée par Tadao Ando avec un cylindre de béton minimaliste magistral au centre de la rotonde. La fresque de la coupole a été restaurée, le contraste ancien/moderne est saisissant. C''est un lieu d''art vivant, parfois déroutant (pigeons empaillés, cire qui fond), à l''architecture époustouflante.');
