wZHPus5EJBsQS6J6eUG0x7kUAt334dKkc2PB4Oj8uFFLuPAh-dlIJlqtkKqRWbP0JSTA_ddXn7NQ1cyrQwQGjAiiExEbGbEOuMfscnIPQCC4VK3eVQqrWha9AHs7a6Dz4J2VTpUkSEyFVQHopxm9J2KkhAOzOAjJG7N4536Q&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Le jardin sauvage est une œuvre d''art en soi.","specials":{"cuisine":[],"drinks":[]}}', 'Dans un bâtiment de verre et d''acier signé Jean Nouvel boulevard Raspail, la Fondation Cartier est une bulle de transparence. Le jardin, conçu comme une friche sauvage par l''artiste Lothar Baumgarten, est une œuvre à part entière. Les expos y sont souvent grandioses et populaires (Ron Mueck, David Lynch, les Yanomami). C''est un lieu qui décloisonne l''art contemporain, le rendant accessible, beau et en lien direct avec la nature urbaine.', 'Le jardin sauvage est une œuvre d''art en soi.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-056', 'Fondation Cartier pour l''art contemporain', 'museum', 'musee', '2 Pl. du Palais Royal', '', 'Dans un bâtiment de verre et d''acier signé Jean Nouvel boulevard Raspail, la Fondation Cartier est une bulle de transparence. Le jardin, conçu comme une friche sauvage par l''artiste Lothar Baumgarten, est une œuvre à part entière. Les expos y sont souvent grandioses et populaires (Ron Mueck, David Lynch, les Yanomami). C''est un lieu qui décloisonne l''art contemporain, le rendant accessible, beau et en lien direct avec la nature urbaine.');
