3gZnNPVK5jnjtI_5ttkDGKWqgz_YXZ7WOxyJdnw8pSu6ONLX0L9qxFTR6biPzsEI4IfsIjWdcsOxEcuFCgHF1jvwcW9BB8sQ_BCZ6Q0g5YdghZV2VgZDvF7vqahyvu6RiUTOld26ACFI7Lhuuy9v0zsgeGS3gDFxyRiHWKdnoD-vWQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Les Nymphéas de Monet sont le clou du spectacle.","specials":{"cuisine":[],"drinks":[]}}', 'Situé au bout du jardin des Tuileries, ce musée est l''écrin sur-mesure d''un chef-d''œuvre absolu : les Nymphéas de Monet. Les deux salles ovales, baignées de lumière naturelle zénithale, ont été conçues par le peintre lui-même pour immerger le spectateur dans ses paysages d''eau. C''est une expérience méditative unique au monde. Le musée abrite aussi la collection Walter-Guillaume (Renoir, Cézanne, Matisse, Picasso...), une concentration de chefs-d''œuvre impressionnistes et modernes dans un format à taille humaine.', 'Les Nymphéas de Monet sont le clou du spectacle.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-057', 'Musée de l''Orangerie', 'museum', 'musee', 'Jardin des Tuileries', '', 'Situé au bout du jardin des Tuileries, ce musée est l''écrin sur-mesure d''un chef-d''œuvre absolu : les Nymphéas de Monet. Les deux salles ovales, baignées de lumière naturelle zénithale, ont été conçues par le peintre lui-même pour immerger le spectateur dans ses paysages d''eau. C''est une expérience méditative unique au monde. Le musée abrite aussi la collection Walter-Guillaume (Renoir, Cézanne, Matisse, Picasso...), une concentration de chefs-d''œuvre impressionnistes et modernes dans un format à taille humaine.');
INSERT INTO places VALUES ('poi-001', 'L''Anticafé Louvre', 'anticafe-louvre', 'café', 'coworking-cafe', 'chill', 48.864181, 2.336264, 1, '10 Rue de Richelieu', '#8ccaf7', 'pin', 1, 3.7, 0, 'https://source.unsplash.com/uFKI74DWFKQ', NULL, 5, 0, '€', 7.5, NULL, NULL, 5, 0, 50, '{"chill":24.2,"festif":3,"culturel":8.8}', '{}', '["café","coworking-cafe"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":7.5,"cocktail_price":0,"coffee_price":5,"dish_price":0,"last_updated":"2025-01-15","budget_avg":5,"type":"cafe","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://source.unsplash.com/uFKI74DWFKQ","gallery":[]}', '[]', NULL, '{"insider_tip":"Visez l angle de la terrasse pour observer le ballet du quartier tout en restant discret.","specials":{"cuisine":[],"drinks":[]}}', 'À deux pas du musée le plus visité au monde, cet espace réinvente totalement le concept du café parisien : ici, on ne paie pas ses consommations, mais le temps passé. C''est une bulle de productivité et de calme idéale pour les nomades digitaux et les créatifs, qui offre un buffet à volonté (snacks, boissons chaudes et fraîches) dans un cadre lumineux et design. Loin du tumulte touristique assourdissant de la rue de Rivoli, c''est le refuge parfait pour travailler quelques heures, organiser un rendez-vous informel ou simplement se poser entre deux visites culturelles. Le concept de ''pay-per-time'' libère l''esprit et permet de se concentrer sur l''essentiel, dans une atmosphère studieuse mais détendue.', 'Visez l angle de la terrasse pour observer le ballet du quartier tout en restant discret.', 'Palais Royal', '[1,7]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-001', 'L''Anticafé Louvre', 'café', 'coworking-cafe', '10 Rue de Richelieu', '', 'À deux pas du musée le plus visité au monde, cet espace réinvente totalement le concept du café parisien : ici, on ne paie pas ses consommations, mais le temps passé. C''est une bulle de productivité et de calme idéale pour les nomades digitaux et les créatifs, qui offre un buffet à volonté (snacks, boissons chaudes et fraîches) dans un cadre lumineux et design. Loin du tumulte touristique assourdissant de la rue de Rivoli, c''est le refuge parfait pour travailler quelques heures, organiser un rendez-vous informel ou simplement se poser entre deux visites culturelles. Le concept de ''pay-per-time'' libère l''esprit et permet de se concentrer sur l''essentiel, dans une atmosphère studieuse mais détendue.');
