MF4KEZ8lLKFbsvDlQgcPMJaaxnkDBA9LTwowRFTsS7G_E--UkM7DT2syO2rUD9DqdSP37EwmNxN_Sy-pXbLppZ0in3SfajctctJIdhufKJfDD3A&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Enclavé au cœur du pouvoir (Ministère de la Culture, Conseil Constitutionnel), ce jardin est un miracle de calme et d''élégance. C''est le mariage parfait entre l''héritage classique (allées de tilleuls taillés au carré, fontaine centrale) et l''audace contemporaine avec les Colonnes de Buren dans la cour d''honneur. C''est le spot chic pour lire sur une chaise verte inclinée, loin des voitures. Les galeries qui l''entourent abritent des boutiques de niche (parfumeurs, vintage de luxe, médailles) et des restaurants mythiques comme le Grand Véfour. Une parenthèse royale.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'Palais Royal', '[1,7]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-041', 'Jardin du Palais Royal', 'parc', 'parc-urbain', '8 Rue de Montpensier', '', 'Enclavé au cœur du pouvoir (Ministère de la Culture, Conseil Constitutionnel), ce jardin est un miracle de calme et d''élégance. C''est le mariage parfait entre l''héritage classique (allées de tilleuls taillés au carré, fontaine centrale) et l''audace contemporaine avec les Colonnes de Buren dans la cour d''honneur. C''est le spot chic pour lire sur une chaise verte inclinée, loin des voitures. Les galeries qui l''entourent abritent des boutiques de niche (parfumeurs, vintage de luxe, médailles) et des restaurants mythiques comme le Grand Véfour. Une parenthèse royale.');
INSERT INTO places VALUES ('poi-026', 'Café Kitsuné', 'cafe-kitsune', 'café', 'coffee-shop', 'chill', 48.865573, 2.337251, 1, '51 Galerie de Montpensier', '#8ccaf7', 'pin', 1, 4, 0, '/images/cafe-kitsune.jpg', NULL, 5.5, 0, '€', NULL, NULL, NULL, 5.5, 0, 50, '{"chill":24,"festif":3,"culturel":8.5}', '{}', '["café","coffee-shop"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":4.8,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":5.5,"dish_price":0,"last_updated":"2025-01-15","budget_avg":5.5,"type":"cafe","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"/images/cafe-kitsune.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Le meilleur Matcha Latte, à déguster sur un banc du Palais Royal.","specials":{"cuisine":[],"drinks":["Café"]}}', 'La marque franco-japonaise de musique et de mode a réussi son pari caféiné. Que ce soit au Palais Royal (le plus beau, niché dans les jardins) ou ailleurs, l''expérience est la même : un design minimaliste et chic, un café latte au lait d''avoine parfait, et ces petits sablés en forme de renard (''kitsune'' en japonais) iconiques. C''est le spot idéal pour une pause esthétique et savoureuse, assis sur un banc à regarder les passants stylés.', 'Le meilleur Matcha Latte, à déguster sur un banc du Palais Royal.', 'Palais Royal - Musée du Louvre', '[1,7]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-026', 'Café Kitsuné', 'café', 'coffee-shop', '51 Galerie de Montpensier', '', 'La marque franco-japonaise de musique et de mode a réussi son pari caféiné. Que ce soit au Palais Royal (le plus beau, niché dans les jardins) ou ailleurs, l''expérience est la même : un design minimaliste et chic, un café latte au lait d''avoine parfait, et ces petits sablés en forme de renard (''kitsune'' en japonais) iconiques. C''est le spot idéal pour une pause esthétique et savoureuse, assis sur un banc à regarder les passants stylés.');
INSERT INTO places VALUES ('poi-102', 'Dalia', 'dalia', 'restaurant', 'levant / partage', 'festif', 48.867868, 2.343554, 2, '93 Rue Montmartre', '#ffab60', 'pin', 1, 4.7, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1ebSMRUs5rt0zZDCJz1s-81LBL3-O6EYNZ6tetOCtYZDx0QuBEl4ihgwiKKXxIl1bt4AW85e9yrBXX1jXBlwHpkYrtoPMdOzLVkLFvRXFSVj0pk5ik_K1lesO4acSALRZWwuy4NuKrj5RjZ2H6Fihh1JWugYcwWzTcsApUMx-WtKMgCUWt_DW4eZy5sZRGKXuyQMen_dQ3pFWg0myj8vJ9cVe3NEYA6UPiPXOmluVVbMC0mr1XeScvP7nMgmPEjc3FDoWxSLWpAWSqij1GoWtnvozP2AgFpkMSRi8g8BRiGQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 22, 0, '€', NULL, NULL, NULL, 0, 22, 50, '{"chill":6.8,"festif":25,"culturel":10}', '{}', '["restaurant","levant / partage"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":22,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":22,"budget_avg":22,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":22,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1ebSMRUs5rt0zZDCJz1s-81LBL3-O6EYNZ6tetOCtYZDx0QuBEl4ihgwiKKXxIl1bt4AW85e9yrBXX1jXBlwHpkYrtoPMdOzLVkLFvRXFSVj0pk5ik_K1lesO4acSALRZWwuy4NuKrj5RjZ2H6Fihh1JWugYcwWzTcsApUMx-WtKMgCUWt_DW4eZy5sZRGKXuyQMen_dQ3pFWg0myj8vJ9cVe3NEYA6UPiPXOmluVVbMC0mr1XeScvP7nMgmPEjc3FDoWxSLWpAWSqij1GoWtnvozP2AgFpkMSRi8g8BRiGQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Dalia est l''une des tables les plus vibrantes du 2ème arrondissement. Ce restaurant dédié à la cuisine levantine propose une farandole d''assiettes à partager inspirées des saveurs d''Israël, du Liban et de Syrie. Sous la houlette du chef Or Bitan, les classiques (houmous, shakshuka, halloumi) sont revisités avec éclat et modernité. Le décor, aux tons terracotta et au mobilier en rotin, baigné par la lumière des grandes baies vitrées, transporte immédiatement les convives sur les rives du Levant. C''est bruyant, joyeux, généreux et idéal pour de grandes tablées festives où le partage est le seul maître-mot.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-102', 'Dalia', 'restaurant', 'levant / partage', '93 Rue Montmartre', '', 'Dalia est l''une des tables les plus vibrantes du 2ème arrondissement. Ce restaurant dédié à la cuisine levantine propose une farandole d''assiettes à partager inspirées des saveurs d''Israël, du Liban et de Syrie. Sous la houlette du chef Or Bitan, les classiques (houmous, shakshuka, halloumi) sont revisités avec éclat et modernité. Le décor, aux tons terracotta et au mobilier en rotin, baigné par la lumière des grandes baies vitrées, transporte immédiatement les convives sur les rives du Levant. C''est bruyant, joyeux, généreux et idéal pour de grandes tablées festives où le partage est le seul maître-mot.');
