INSERT INTO places VALUES ('poi-092', 'FAT Paris', 'fat-paris', 'bar', 'hip hop bar', 'festif', 48.862668, 2.361301, 3, '8 Rue de Beauce', '#ffab60', 'pin', 1, 0, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3Dc1U8ewhCL7sqj2Z9ZSOehiqqSF-a4Was61Lk-O2H2sX4hvHBN_W8nEd5UZTlKOVH9Zn-Udq-x1h4IRVTDIRKDrZe32YWy2NgWUNgVq0-DDvIxOJCIwGQk5Le1HwHOh3fzv0B02aYjUP0t5M5Hs_MyzPE4iQ7uqxazVXrE6DMNRBk2KgPJBFQh9G99SA-0eMSFBKqck3P8wK3--pH8fE4z6vEvvsR24___nODGEQXtJuuzQn-IXO-RoyCzeFMvUomwvEHodPw3G0asY9Q0SsirqSG3ACEuOjH4oqrUsR1Dw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 7, 0, '€', 7, NULL, NULL, 0, 0, 50, '{"chill":4.4,"festif":25,"culturel":8}', '{}', '["bar","hip hop bar"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":12,"is_free":false,"pint_price":7,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":7,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3Dc1U8ewhCL7sqj2Z9ZSOehiqqSF-a4Was61Lk-O2H2sX4hvHBN_W8nEd5UZTlKOVH9Zn-Udq-x1h4IRVTDIRKDrZe32YWy2NgWUNgVq0-DDvIxOJCIwGQk5Le1HwHOh3fzv0B02aYjUP0t5M5Hs_MyzPE4iQ7uqxazVXrE6DMNRBk2KgPJBFQh9G99SA-0eMSFBKqck3P8wK3--pH8fE4z6vEvvsR24___nODGEQXtJuuzQn-IXO-RoyCzeFMvUomwvEHodPw3G0asY9Q0SsirqSG3ACEuOjH4oqrUsR1Dw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'FAT (French Art Touch) est le temple parisien de la culture urbaine. Dans cet immense espace de 250m² caché au cœur du Marais, le hip-hop est roi et le graffiti est partout, des murs aux tables. L''ambiance y est explosive : on y vient pour s''affronter au beer pong, redécouvrir les classiques du rap américain ou vibrer lors des DJ sets et concerts live. Pour éponger les cocktails créatifs aux noms de légendes du rap, l''établissement propose des pizzas XXL et des hot-dogs. C''est bruyant, c''est brut, c''est joyeux et c''est assurément l''un des lieux les plus dynamiques du quartier.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-092', 'FAT Paris', 'bar', 'hip hop bar', '8 Rue de Beauce', '', 'FAT (French Art Touch) est le temple parisien de la culture urbaine. Dans cet immense espace de 250m² caché au cœur du Marais, le hip-hop est roi et le graffiti est partout, des murs aux tables. L''ambiance y est explosive : on y vient pour s''affronter au beer pong, redécouvrir les classiques du rap américain ou vibrer lors des DJ sets et concerts live. Pour éponger les cocktails créatifs aux noms de légendes du rap, l''établissement propose des pizzas XXL et des hot-dogs. C''est bruyant, c''est brut, c''est joyeux et c''est assurément l''un des lieux les plus dynamiques du quartier.');
INSERT INTO places VALUES ('poi-087', 'Istr', 'istr', 'restaurant', 'seafood & cocktails', 'culturel', 48.867413, 2.357535, 3, '41 Rue Notre Dame de Nazareth', '#c499ff', 'pin', 1, 4.6, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2gih_uezw7RucIIgFyMdCXec4ZuzGQDagPeRulb_jXErScDCZjS2Nsfv3AUjDyXnJ5qt7i73vgyvggBN5e01jTe6sgr9HGbVQAE2p1-lOQJp42lbLmlvjDRcVB5cOERh1QyD1vh-vBOx-RVEBJ-IQGTZpmgCOCuJbz7-RhqYCyrZ4aRnQCk1umzOq4OABYmWD1rU-6WG2X2YwraXMcfNjMr5B0RXIYx4JXOYEZmkjSZtW_RUIt7AyS3riBkN7ApH-YiuTOwSbonWBJAnRJEFuNEx4PJlnWdaxRHH55kcgOlQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 28, 0, '€', NULL, NULL, NULL, 0, 28, 50, '{"chill":7.2,"festif":6,"culturel":25}', '{}', '["restaurant","seafood & cocktails"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":28,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":28,"budget_avg":28,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":28,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2gih_uezw7RucIIgFyMdCXec4ZuzGQDagPeRulb_jXErScDCZjS2Nsfv3AUjDyXnJ5qt7i73vgyvggBN5e01jTe6sgr9HGbVQAE2p1-lOQJp42lbLmlvjDRcVB5cOERh1QyD1vh-vBOx-RVEBJ-IQGTZpmgCOCuJbz7-RhqYCyrZ4aRnQCk1umzOq4OABYmWD1rU-6WG2X2YwraXMcfNjMr5B0RXIYx4JXOYEZmkjSZtW_RUIt7AyS3riBkN7ApH-YiuTOwSbonWBJAnRJEFuNEx4PJlnWdaxRHH55kcgOlQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Istr (''huître'' en breton) réinvente le bar à huîtres traditionnel en y injectant une dose de mixology new-yorkaise. Niché dans le Marais, cet établissement lumineux au décor soigné (marbre, bois, touches cuivrées) propose de déguster des produits de la mer d''une fraîcheur exemplaire accompagnés de cocktails créatifs spécifiquement conçus pour se marier aux saveurs iodées. Que ce soit pour un ceviche minute ou une douzaine de n°3 spéciales, Istr offre une parenthèse élégante et contemporaine, idéale pour un ''shellfish & cocktail'' entre initiés.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-087', 'Istr', 'restaurant', 'seafood & cocktails', '41 Rue Notre Dame de Nazareth', '', 'Istr (''huître'' en breton) réinvente le bar à huîtres traditionnel en y injectant une dose de mixology new-yorkaise. Niché dans le Marais, cet établissement lumineux au décor soigné (marbre, bois, touches cuivrées) propose de déguster des produits de la mer d''une fraîcheur exemplaire accompagnés de cocktails créatifs spécifiquement conçus pour se marier aux saveurs iodées. Que ce soit pour un ceviche minute ou une douzaine de n°3 spéciales, Istr offre une parenthèse élégante et contemporaine, idéale pour un ''shellfish & cocktail'' entre initiés.');
