INSERT INTO places VALUES ('poi-084', 'Little Red Door', 'little-red-door', 'bar', 'speakeasy', 'culturel', 48.86361, 2.363634, 3, '60 Rue Charlot', '#c499ff', 'pin', 1, 4.4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1-hVEWEFWQe-JzAPriYKNqlHi1hGfPntLB9BEozpkAr5n9HBQ6J3BCIp-juFDQ2XTt4JmpalD0eQWbwrL7Yrof_8cOusbAXpN-7doRh6Zk57oLtvvGCqatSw23VGkwtmxMkqufWI7AtdrlT8ZzwiSFbymqQPs4whci4IsDU30LcQp7_UssE-YXf_dqec6LNh6QZtuvVuQL-eZmjlOYA_5cvfoX2Ivu0qXeIkJLF2EZ5bvwpCvXD1Z-nXTRQmYd03eHvHwBR5dFVHc-OThbum9Wx62IA7yJ-naHhElimRH26g&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 9, 0, '€', 9, 16, NULL, 0, 0, 50, '{"chill":5.4,"festif":9,"culturel":25}', '{}', '["bar","speakeasy"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":18,"is_free":false,"pint_price":9,"cocktail_price":16,"coffee_price":0,"dish_price":0,"budget_avg":9,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1-hVEWEFWQe-JzAPriYKNqlHi1hGfPntLB9BEozpkAr5n9HBQ6J3BCIp-juFDQ2XTt4JmpalD0eQWbwrL7Yrof_8cOusbAXpN-7doRh6Zk57oLtvvGCqatSw23VGkwtmxMkqufWI7AtdrlT8ZzwiSFbymqQPs4whci4IsDU30LcQp7_UssE-YXf_dqec6LNh6QZtuvVuQL-eZmjlOYA_5cvfoX2Ivu0qXeIkJLF2EZ5bvwpCvXD1Z-nXTRQmYd03eHvHwBR5dFVHc-OThbum9Wx62IA7yJ-naHhElimRH26g&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Ne cherchez pas de menu classique, chaque ''collection'' est un livre d''art.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Little Red Door n''est pas seulement un bar, c''est une institution mondiale de la mixology. Depuis sa petite porte rouge de la rue Charlot, ce speakeasy réinvente sans cesse l''expérience cocktail à travers des menus conceptuels basés sur l''art, l''anthropologie ou plus récemment l''agriculture locale. Son décor feutré de briques apparentes et de sofas en velours crée une atmosphère de salon new-yorkais intime et chaleureux. Ici, l''accueil est aussi précis que le dosage des alcools, offrant une immersion totale dans la création liquide contemporaine.', 'Ne cherchez pas de menu classique, chaque ''collection'' est un livre d''art.', 'Filles du Calvaire', '[8]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-084', 'Little Red Door', 'bar', 'speakeasy', '60 Rue Charlot', '', 'Little Red Door n''est pas seulement un bar, c''est une institution mondiale de la mixology. Depuis sa petite porte rouge de la rue Charlot, ce speakeasy réinvente sans cesse l''expérience cocktail à travers des menus conceptuels basés sur l''art, l''anthropologie ou plus récemment l''agriculture locale. Son décor feutré de briques apparentes et de sofas en velours crée une atmosphère de salon new-yorkais intime et chaleureux. Ici, l''accueil est aussi précis que le dosage des alcools, offrant une immersion totale dans la création liquide contemporaine.');
INSERT INTO places VALUES ('poi-019', 'La Gaîté Lyrique', 'gaite-lyrique', 'museum', 'espace-culturel', 'culturel', 48.866697, 2.353563, 3, '3 bis Rue Papin', '#c499ff', 'pin', 1, 4.5, 0, '/images/gaite-lyrique.jpg', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":6,"festif":6.5,"culturel":24.5}', '{}', '["museum","espace-culturel"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":12,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":15,"type":"museum","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"/images/gaite-lyrique.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Top pour bosser l''après-midi avec un café, le wifi est ultra-rapide.","specials":{"cuisine":[],"drinks":[]}}', 'Ancien théâtre du XIXe siècle reconverti en centre dédié aux cultures numériques et aux arts digitaux. Caché derrière sa façade Second Empire, l''intérieur est un vaisseau futuriste où se croisent expositions immersives, concerts électroniques pointus et balls de voguing légendaires. Le Foyer historique à l''étage, miraculeusement préservé, est une pépite dorée à découvrir. C''est le QG de la scène tech-art parisienne.', 'Top pour bosser l''après-midi avec un café, le wifi est ultra-rapide.', 'Réaumur-Sébastopol', '[3,4]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-019', 'La Gaîté Lyrique', 'museum', 'espace-culturel', '3 bis Rue Papin', '', 'Ancien théâtre du XIXe siècle reconverti en centre dédié aux cultures numériques et aux arts digitaux. Caché derrière sa façade Second Empire, l''intérieur est un vaisseau futuriste où se croisent expositions immersives, concerts électroniques pointus et balls de voguing légendaires. Le Foyer historique à l''étage, miraculeusement préservé, est une pépite dorée à découvrir. C''est le QG de la scène tech-art parisienne.');
INSERT INTO places VALUES ('poi-225', 'The Cambridge Public House', 'the-cambridge-public-house', 'bar', 'pub-cocktail', 'festif', 48.861443, 2.364139, 3, '8 Rue de Poitou', '#ffab60', 'pin', 1, 4.7, 0, 'https://images.unsplash.com/photo-1514933651103-005eec06c04b?auto=format&fit=crop&q=80&w=1000', NULL, 10, 0, '€', 10, 14, NULL, 0, 0, 50, '{"chill":10,"festif":22,"culturel":5}', '{}', '["bar","pub-cocktail"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":25,"is_free":false,"pint_price":10,"cocktail_price":14,"coffee_price":0,"dish_price":0,"budget_avg":10,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://images.unsplash.com/photo-1514933651103-005eec06c04b?auto=format&fit=crop&q=80&w=1000","gallery":[]}', '[]', NULL, '{"insider_tip":"Ils font partie de la prestigieuse liste des ''World''s 50 Best'' mais vous traiteront comme un habitué dès la première visite.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'The Cambridge Public House réussi le pari audacieux de marier la convivialité d''un pub anglais traditionnel à l''exigence technique d''un bar à cocktails de classe mondiale. Dans un quartier du Marais en perpétuelle effervescence, ce lieu se distingue par son atmosphère authentique — bois sombre, banquettes en cuir vert et accueil chaleureux — tout en proposant une carte de cocktails saisonnière axée sur la durabilité. Ici, la mixologie est précise et réfléchie, mais l''esprit reste celui d''un pub de quartier où l''on se retrouve pour une craft beer ou leur célèbre sausage roll. Un équilibre parfait entre décontraction et excellence.', 'Ils font partie de la prestigieuse liste des ''World''s 50 Best'' mais vous traiteront comme un habitué dès la première visite.', 'Saint-Sébastien - Froissart', '[8]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-225', 'The Cambridge Public House', 'bar', 'pub-cocktail', '8 Rue de Poitou', '', 'The Cambridge Public House réussi le pari audacieux de marier la convivialité d''un pub anglais traditionnel à l''exigence technique d''un bar à cocktails de classe mondiale. Dans un quartier du Marais en perpétuelle effervescence, ce lieu se distingue par son atmosphère authentique — bois sombre, banquettes en cuir vert et accueil chaleureux — tout en proposant une carte de cocktails saisonnière axée sur la durabilité. Ici, la mixologie est précise et réfléchie, mais l''esprit reste celui d''un pub de quartier où l''on se retrouve pour une craft beer ou leur célèbre sausage roll. Un équilibre parfait entre décontraction et excellence.');
