INSERT INTO places VALUES ('poi-104', 'Miznon Marais', 'miznon-marais', 'restaurant', 'street food israélien', 'festif', 48.85716, 2.358981, 4, '22 Rue des Écouffes', '#ffab60', 'pin', 1, 4.3, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3V73QitMQ-fb2iOz15qhDWxJg3dMhJu0GPGsyqV0AX1Gea1-8AVyYq-qnf1H7wbGJ_qq38idh5oMTwOoeumV9IskgPVaa_vtjUhWDHu6-JcC-e3rYjgqvB5SU2Y2L_x1lODGNXzg-teVHjUm7PHNXrwR07BQ6F9vwo6CTSrMXwDLO5RMOInsHHSAezZGyOByum7qPVGBX3fXMKsQpiQkRQ1pp869h_qDlFabMW7gKiCKvqjVW84P8i0fKPw9owlvVzY74DzXnnJdDd86vxCaCFd5Hse47kflLyKmo9kato6Q&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 13.5, 0, '€', NULL, NULL, NULL, 0, 13.5, 50, '{"chill":6.8,"festif":25,"culturel":6}', '{}', '["restaurant","street food israélien"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":13.5,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":13.5,"budget_avg":13.5,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":13.5,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3V73QitMQ-fb2iOz15qhDWxJg3dMhJu0GPGsyqV0AX1Gea1-8AVyYq-qnf1H7wbGJ_qq38idh5oMTwOoeumV9IskgPVaa_vtjUhWDHu6-JcC-e3rYjgqvB5SU2Y2L_x1lODGNXzg-teVHjUm7PHNXrwR07BQ6F9vwo6CTSrMXwDLO5RMOInsHHSAezZGyOByum7qPVGBX3fXMKsQpiQkRQ1pp869h_qDlFabMW7gKiCKvqjVW84P8i0fKPw9owlvVzY74DzXnnJdDd86vxCaCFd5Hse47kflLyKmo9kato6Q&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Miznon Marais est le sanctuaire de la street-food israélienne décomplexée imaginé par Eyal Shani. Ici, pas de réservation et souvent une file d''attente sur le trottoir. À l''intérieur, c''est le chaos fertile : on hurle votre nom pour votre commande, la musique est à fond, et des légumes frais trônent partout sur les murs. On y dévore des pitas incroyables (bœuf bourguignon, kebab d''agneau, ratatouille) et le cultissime chou-fleur rôti entier, devenu un emblème du quartier. C''est bruyant, c''est généreux, c''est authentique et c''est assurément l''une des expériences les plus énergisantes du Marais.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-104', 'Miznon Marais', 'restaurant', 'street food israélien', '22 Rue des Écouffes', '', 'Miznon Marais est le sanctuaire de la street-food israélienne décomplexée imaginé par Eyal Shani. Ici, pas de réservation et souvent une file d''attente sur le trottoir. À l''intérieur, c''est le chaos fertile : on hurle votre nom pour votre commande, la musique est à fond, et des légumes frais trônent partout sur les murs. On y dévore des pitas incroyables (bœuf bourguignon, kebab d''agneau, ratatouille) et le cultissime chou-fleur rôti entier, devenu un emblème du quartier. C''est bruyant, c''est généreux, c''est authentique et c''est assurément l''une des expériences les plus énergisantes du Marais.');
