INSERT INTO places VALUES ('poi-226', 'Sherry Butt', 'sherry-butt', 'bar', 'bar-a-cocktail', 'chill', 48.853248, 2.364147, 4, '20 Rue Beautreillis', '#8ccaf7', 'pin', 1, 4.4, 0, 'https://images.unsplash.com/photo-1514933651103-005eec06c04b?auto=format&fit=crop&q=80&w=1000', NULL, 0, 0, '€', NULL, 13, NULL, 0, 0, 50, '{"chill":20,"festif":5,"culturel":10}', '{}', '["bar","bar-a-cocktail"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":30,"is_free":false,"pint_price":0,"cocktail_price":13,"coffee_price":0,"dish_price":0,"budget_avg":0,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://images.unsplash.com/photo-1514933651103-005eec06c04b?auto=format&fit=crop&q=80&w=1000","gallery":[]}', '[]', NULL, '{"insider_tip":"Le changement de nom pour ''Memento'' ne change pas la qualité : les barmen historiques sont toujours là.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Sherry Butt est le havre de paix idéal pour les esthètes en quête de tranquillité et de spiritueux d''exception dans le Marais. Ce bar à l''allure de loft industriel chic – pierre apparente, métal et cuir profond – se spécialise dans les whiskies du monde entier, avec une affection particulière pour les fûts de Sherry, et les cocktails de création d''une grande complexité aromatique. L''ambiance y est apaisée, la musique est au bon volume, et l''hospitalité est irréprochable. C''est l''un de ces lieux précieux où l''on vient pour savourer le temps, une excellente quille à la main, dans un cadre serein et sophistiqué qui invite à la confidence.', 'Le changement de nom pour ''Memento'' ne change pas la qualité : les barmen historiques sont toujours là.', 'Bastille', '[1,5,8]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-226', 'Sherry Butt', 'bar', 'bar-a-cocktail', '20 Rue Beautreillis', '', 'Sherry Butt est le havre de paix idéal pour les esthètes en quête de tranquillité et de spiritueux d''exception dans le Marais. Ce bar à l''allure de loft industriel chic – pierre apparente, métal et cuir profond – se spécialise dans les whiskies du monde entier, avec une affection particulière pour les fûts de Sherry, et les cocktails de création d''une grande complexité aromatique. L''ambiance y est apaisée, la musique est au bon volume, et l''hospitalité est irréprochable. C''est l''un de ces lieux précieux où l''on vient pour savourer le temps, une excellente quille à la main, dans un cadre serein et sophistiqué qui invite à la confidence.');
