kZxGWquuswhSyAslX8hHkCgTWxBVXjV1Hxxv9Nt7O5Yd-D9zT_Z51kQ58rFejhpVje-Md6LcaRyErtXnxpEQIpVeLNSRJuCcs3GF1e4eu7nYkb3zz3Q4s0yc-Mqko6lrJuy&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'La plus ancienne place de Paris (inaugurée en 1612 pour les fiançailles de Louis XIII) est aussi la plus harmonieuse. C''est un carré parfait de 36 pavillons de brique rouge et de pierre blanche, aux toits d''ardoise bleue, qui entourent le Square Louis XIII. C''est le cœur aristocratique du Marais. Victor Hugo y a vécu (sa maison se visite). Les arcades abritent des galeries d''art et des cafés chics. S''allonger sur l''herbe au centre de la place l''été, entouré de tant d''histoire et de symétrie, est un privilège royal accessible à tous.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'Saint-Paul / Chemin Vert', '[1,8]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-040', 'Place des Vosges', 'parc', 'parc-urbain', 'Pl. des Vosges', '', 'La plus ancienne place de Paris (inaugurée en 1612 pour les fiançailles de Louis XIII) est aussi la plus harmonieuse. C''est un carré parfait de 36 pavillons de brique rouge et de pierre blanche, aux toits d''ardoise bleue, qui entourent le Square Louis XIII. C''est le cœur aristocratique du Marais. Victor Hugo y a vécu (sa maison se visite). Les arcades abritent des galeries d''art et des cafés chics. S''allonger sur l''herbe au centre de la place l''été, entouré de tant d''histoire et de symétrie, est un privilège royal accessible à tous.');
INSERT INTO places VALUES ('poi-018', 'Les Nautes', 'les-nautes', 'bar', 'péniche-bar', 'chill', 48.852247, 2.360301, 4, 'Port des Célestins', '#8ccaf7', 'pin', 1, 4.3, 0, '/images/les-nautes.jpg', NULL, 9, 0, '€', 9, NULL, NULL, 0, 18, 50, '{"chill":23.5,"festif":6,"culturel":6.5}', '{}', '["bar","péniche-bar"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":9,"cocktail_price":0,"coffee_price":0,"dish_price":18,"budget_avg":9,"type":"bar","menu_items":[],"_debug_manual_dish_price":18,"_debug_median_dish_price":null}', '{"hero":"/images/les-nautes.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Le spot parfait pour un date avant que la musique ne monte vers 22h.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'L''une des rares terrasses de Paris orientée plein sud et... pieds dans l''eau ! Située sur les quais de Seine face à l''Île Saint-Louis, cette maisonnette en pierre sert des bières et des planches simples dans une ambiance de vacances absolues. Quand le soleil tape, c''est le spot idéal pour bronzer en regardant passer les bateaux-mouches. C''est sans prétention, démocratique et magique au coucher du soleil.', 'Le spot parfait pour un date avant que la musique ne monte vers 22h.', 'Sully-Morland', '[7]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-018', 'Les Nautes', 'bar', 'péniche-bar', 'Port des Célestins', '', 'L''une des rares terrasses de Paris orientée plein sud et... pieds dans l''eau ! Située sur les quais de Seine face à l''Île Saint-Louis, cette maisonnette en pierre sert des bières et des planches simples dans une ambiance de vacances absolues. Quand le soleil tape, c''est le spot idéal pour bronzer en regardant passer les bateaux-mouches. C''est sans prétention, démocratique et magique au coucher du soleil.');
