INSERT INTO places_fts VALUES ('poi-129', 'Le Piano Vache', 'bar', 'bar-rock', '8 Rue Laplace', '', 'Entrer au Piano Vache, c''est plonger dans un Paris de nuit qui semble n''avoir jamais changé. Murs noirs couverts d''affiches vintage, banquettes usées et lumière tamisée créent une atmosphère de rock''n''roll intemporel. Les soirées jazz manouche du lundi sont légendaires, tout comme la playlist rock qui anime les nuits du weekend. Un refuge pour ceux qui détestent les bars lisses et cherchent l''âme brute du 5ème.');
