INSERT INTO places_fts VALUES ('poi-le-royal', 'Le Royal', 'restaurant', 'brasserie bar pizza terrasse happy-hour', '90 Boulevard de Port-Royal', '', 'Brasserie d''angle historique au carrefour du Val-de-Grâce. Le Royal se distingue par son sens du sourcing (Jambon Prince de Paris, Saumon Bömlö) et ses horaires de Happy Hour qui s''étirent jusqu''au bout de la nuit sur une grande terrasse chauffée.');
