q-NVKHH9vbAtrvwt9zruxP1pdTsiVl6hOOEn2LD8_ah8cOpawWKBLc4qBxTFTX2_-BIU8xi6mK5ETFUyqNP5qvSnnSSuqG9_IhBpuaLgVZQwr59isN9-L&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Le jardin de sculptures est accessible pour 4€ (sans le musée).","specials":{"cuisine":[],"drinks":[]}}', 'L''Hôtel Biron, où Rodin a vécu et travaillé, est sans doute l''un des plus beaux hôtels particuliers de Paris. Mais la magie opère surtout dans le jardin de sculptures de 3 hectares. Se promener au milieu des rosiers et découvrir le Penseur ou la Porte de l''Enfer en plein air, avec le dôme des Invalides en toile de fond, est un moment de grâce. L''intérieur du musée, baigné de lumière, présente les œuvres en plâtre, marbre et bronze dans leur cadre d''origine. Romantique à souhait.', 'Le jardin de sculptures est accessible pour 4€ (sans le musée).', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-055', 'Musée Rodin', 'museum', 'musee', '77 Rue de Varenne', '', 'L''Hôtel Biron, où Rodin a vécu et travaillé, est sans doute l''un des plus beaux hôtels particuliers de Paris. Mais la magie opère surtout dans le jardin de sculptures de 3 hectares. Se promener au milieu des rosiers et découvrir le Penseur ou la Porte de l''Enfer en plein air, avec le dôme des Invalides en toile de fond, est un moment de grâce. L''intérieur du musée, baigné de lumière, présente les œuvres en plâtre, marbre et bronze dans leur cadre d''origine. Romantique à souhait.');
