,"drinks":[]}}', 'Situé à l''entrée des Tuileries, face à l''Orangerie, ce bâtiment Second Empire est dédié à l''image contemporaine (photo, vidéo). Sa programmation est souvent engagée, politique et documentaire (Dorothea Lange, Gordon Matta-Clark). C''est un musée à taille humaine, lumineux, qui offre une pause culturelle intelligente avant d''aller marcher dans le jardin des Tuileries. La librairie est l''une des meilleures de Paris pour la photographie.', 'Temple de la photographie à la Concorde.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-058', 'Jeu de Paume', 'museum', 'musee', '1 Pl. de la Concorde', '', 'Situé à l''entrée des Tuileries, face à l''Orangerie, ce bâtiment Second Empire est dédié à l''image contemporaine (photo, vidéo). Sa programmation est souvent engagée, politique et documentaire (Dorothea Lange, Gordon Matta-Clark). C''est un musée à taille humaine, lumineux, qui offre une pause culturelle intelligente avant d''aller marcher dans le jardin des Tuileries. La librairie est l''une des meilleures de Paris pour la photographie.');
INSERT INTO places VALUES ('poi-177', 'Le Bristol Bar', 'le-bristol-bar', 'bar', 'palace-bar', 'festif', 48.871723, 2.314821, 8, 'Hôtel Le Bristol Paris, 112 Rue du Faubourg Saint-Honoré', '#ffab60', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3jybof_zMNW3ytXsuRV_Ue8hp9TATasVbFQHNg8_Ty-42z-II4q3j__kN9-dl_QJyL43voUx8clJ3lC3mH-R51Qncjd6M3cCn7ftp9JEb6xmz4sim0YOKisq86LGUIEE8OBq_mq-wR7Xk-AUJ0u-O8ue_VU13T6WyFNmoNkKdbLYPF1ojGhSDN7aF8oDYuhNf1iFVsvezFMq5u1knOGslaWbwt8XcxyTuLOH80DjV92HPQRpwUaiSa-4dmkOo65meJDwIVdvu2Xs9lGw1Dgf91HAowb-izJuaLralN1Bl0aA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 0, 0, '€', NULL, 22, NULL, 0, 0, 50, '{"chill":6,"festif":23,"culturel":5}', '{}', '["bar","palace-bar"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":22,"coffee_price":0,"dish_price":0,"budget_avg":0,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3jybof_zMNW3ytXsuRV_Ue8hp9TATasVbFQHNg8_Ty-42z-II4q3j__kN9-dl_QJyL43voUx8clJ3lC3mH-R51Qncjd6M3cCn7ftp9JEb6xmz4sim0YOKisq86LGUIEE8OBq_mq-wR7Xk-AUJ0u-O8ue_VU13T6WyFNmoNkKdbLYPF1ojGhSDN7aF8oDYuhNf1iFVsvezFMq5u1knOGslaWbwt8XcxyTuLOH80DjV92HPQRpwUaiSa-4dmkOo65meJDwIVdvu2Xs9lGw1Dgf91HAowb-izJuaLralN1Bl0aA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Le bar du Bristol est le refuge secret du Triangle d''Or. Dans un décor de boiseries sombres, cheminée et velours précieux, on y déguste des cocktails de haute volée loin du tumulte des Champs-Élysées. Service de palace, attentionné et discret, atmosphère feutrée et compositions de spiritueux rares en font un lieu d''exception. C''est l''élégance parisienne poussée à son paroxysme, où chaque détail est pensé pour créer une bulle de luxe et de sérénité.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-177', 'Le Bristol Bar', 'bar', 'palace-bar', 'Hôtel Le Bristol Paris, 112 Rue du Faubourg Saint-Honoré', '', 'Le bar du Bristol est le refuge secret du Triangle d''Or. Dans un décor de boiseries sombres, cheminée et velours précieux, on y déguste des cocktails de haute volée loin du tumulte des Champs-Élysées. Service de palace, attentionné et discret, atmosphère feutrée et compositions de spiritueux rares en font un lieu d''exception. C''est l''élégance parisienne poussée à son paroxysme, où chaque détail est pensé pour créer une bulle de luxe et de sérénité.');
INSERT INTO places VALUES ('poi-183', 'Le Piaf', 'le-piaf-paris', 'restaurant', 'festif', 'chill', 48.872055, 2.312668, 8, '38 Rue Jean Mermoz', '#8ccaf7', 'pin', 1, 3.8, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN018cN8Ba8CeSb7bHBV0BCmw0sHkVNoVluggIZyoamlfumcirH6m6qx7b9KkVJvY58r_0TfSflHubcUUFoFVKkR8VhjwTVMHsS9Ef8KZS-8ZqjKgZwgXBDGKTxINmYHk_ITn5ws0TZwz8UygIGZ0PbnN_QSBVGoBDBUl8IwRssSf5AnYWs5y6WCoykGv54OElN_yKL4ZY4IA_y7XcE0-xZev7Vpd4LMyHSnvOuoWljcokyqN2vQVbENoQJfmSfNdNc8Qgc7jdIAtFPmhYpNCkd_e-BYcA4VBDwiZSQXN2bcyQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 30, 0, '€', NULL, NULL, NULL, 0, 30, 50, '{"chill":21,"festif":4,"culturel":5}', '{}', '["restaurant","festif"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":52,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":30,"budget_avg":30,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":30,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN018cN8Ba8CeSb7bHBV0BCmw0sHkVNoVluggIZyoamlfumcirH6m6qx7b9KkVJvY58r_0TfSflHubcUUFoFVKkR8VhjwTVMHsS9Ef8KZS-8ZqjKgZwgXBDGKTxINmYHk_ITn5ws0TZwz8UygIGZ0PbnN_QSBVGoBDBUl8IwRssSf5AnYWs5y6WCoykGv54OElN_yKL4ZY4IA_y7XcE0-xZev7Vpd4LMyHSnvOuoWljcokyqN2vQVbENoQJfmSfNdNc8Qgc7jdIAtFPmhYpNCkd_e-BYcA4VBDwiZSQXN2bcyQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Le Piaf est le nid douillet des oiseaux de nuit parisiens. Entre restaurant feutré et piano-bar endiablé, ce lieu mise sur l''élégance et la fête bourgeoise. On y dîne sous des lumières tamisées avant que le piano-voix ne s emballe et que tout le monde ne finisse par reprendre en chœur les classiques français et internationaux. Cuisine réconfortante (foie gras, bar rôti) et cocktails signatures composent la partition idéale d''une soirée rive droite réussie.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-183', 'Le Piaf', 'restaurant', 'festif', '38 Rue Jean Mermoz', '', 'Le Piaf est le nid douillet des oiseaux de nuit parisiens. Entre restaurant feutré et piano-bar endiablé, ce lieu mise sur l''élégance et la fête bourgeoise. On y dîne sous des lumières tamisées avant que le piano-voix ne s emballe et que tout le monde ne finisse par reprendre en chœur les classiques français et internationaux. Cuisine réconfortante (foie gras, bar rôti) et cocktails signatures composent la partition idéale d''une soirée rive droite réussie.');
