s.","specials":{"cuisine":[],"drinks":[]}}', 'Le Raspoutine est une légende de la nuit slave à Paris. Avec son décor baroque rouge sang, ses broderies russes et son éclairage tamisé, ce club est une institution de l''exclusivité. On y bascule dans une autre dimension dès le pas de la porte : entre cabaret russe historique et clubbing deep house pointu. Une sélection drastique à l''entrée garantit une faune haut de gamme pour des nuits qui ne s arrêtent jamais dans un luxe de velours et de secret.', 'Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-180', 'Raspoutine', 'club', 'club-select', '58 Rue de Bassano', '', 'Le Raspoutine est une légende de la nuit slave à Paris. Avec son décor baroque rouge sang, ses broderies russes et son éclairage tamisé, ce club est une institution de l''exclusivité. On y bascule dans une autre dimension dès le pas de la porte : entre cabaret russe historique et clubbing deep house pointu. Une sélection drastique à l''entrée garantit une faune haut de gamme pour des nuits qui ne s arrêtent jamais dans un luxe de velours et de secret.');
INSERT INTO places VALUES ('poi-028', 'Parc Monceau', 'parc-monceau', 'parc', 'jardin-romantique', 'chill', 48.879683, 2.308955, 8, '35 Boulevard de Courcelles', '#8ccaf7', 'pin', 1, 4.6, 0, '/images/parc-monceau.jpg', NULL, 0, 1, '€', 0, 0, 0, 0, 0, 50, '{"chill":24.8,"festif":2,"culturel":7.5}', '{}', '["parc","jardin-romantique"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":2,"is_free":true,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":0,"type":"parc","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"/images/parc-monceau.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Le parc le plus élégant et le plus ''proustien'' de Paris. Entouré d''hôtels particuliers somptueux, on y accède par des grilles dorées. C''est un jardin de folies architecturales : une pyramide égyptienne, une colonnade corinthienne au bord d''un bassin (la Naumachie), un pont vénitien... C''est le jardin des enfants chics du 8ème et des nounous en uniforme. Idéal pour lire un livre sur un banc en se prenant pour un héros romantique.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'Monceau', '[2]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-028', 'Parc Monceau', 'parc', 'jardin-romantique', '35 Boulevard de Courcelles', '', 'Le parc le plus élégant et le plus ''proustien'' de Paris. Entouré d''hôtels particuliers somptueux, on y accède par des grilles dorées. C''est un jardin de folies architecturales : une pyramide égyptienne, une colonnade corinthienne au bord d''un bassin (la Naumachie), un pont vénitien... C''est le jardin des enfants chics du 8ème et des nounous en uniforme. Idéal pour lire un livre sur un banc en se prenant pour un héros romantique.');
INSERT INTO places VALUES ('poi-098', 'Bleu Bao', 'bleu-bao', 'restaurant', 'chinois / tea house', 'culturel', 48.876927, 2.33839, 9, '8 Rue Saint-Lazare', '#c499ff', 'pin', 1, 4.8, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3o52rGDFrCm4zixHj4iLb-XY-9r7xXhGTAzkScZzceFk3xEL_WVZXjNRsszONo2aUxCKAhGEL30e2FEmDHkVPcmG_5V_VEKooaOEB_YUnUNM-QU-OQTuYgVx1sHeKQtxM-o5OnJ4UX7qzW2v2xoT0UVeJ__BNPzfnF7Y7PGp12jc6MJFMbiP5eGIHmJ4LDxev4G_hV-Z-vcYjNo07Y6IAYj2u-Ndvh2VYNE9vJn1RhWsvuqtK8kUHiu_tAUBTliGAs-sB7MvbY3Y0aDQyDKgWMkLsDoWxDfqSlDMTAPC-clg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 14, 0, '€', NULL, NULL, NULL, 0, 14, 50, '{"chill":6.8,"festif":7.3,"culturel":25}', '{}', '["restaurant","chinois / tea house"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":14,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":14,"budget_avg":14,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":14,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3o52rGDFrCm4zixHj4iLb-XY-9r7xXhGTAzkScZzceFk3xEL_WVZXjNRsszONo2aUxCKAhGEL30e2FEmDHkVPcmG_5V_VEKooaOEB_YUnUNM-QU-OQTuYgVx1sHeKQtxM-o5OnJ4UX7qzW2v2xoT0UVeJ__BNPzfnF7Y7PGp12jc6MJFMbiP5eGIHmJ4LDxev4G_hV-Z-vcYjNo07Y6IAYj2u-Ndvh2VYNE9vJn1RhWsvuqtK8kUHiu_tAUBTliGAs-sB7MvbY3Y0aDQyDKgWMkLsDoWxDfqSlDMTAPC-clg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Bleu Bao est la version raffinée et esthète de la Bao Family. Installé rue Saint-Lazare, cet établissement rend hommage aux maisons de thé traditionnelles chinoises avec un décor bleu azur et une porcelaine délicate. L''atmosphère y est plus feutrée et sereine que dans les autres adresses du groupe, idéale pour un déjeuner chic ou un dîner intimiste. Outre les excellents dim-sums et baos, le lieu propose une sélection de thés d''exception et des cocktails inspirés de l''Asie. C''est le mariage parfait entre l''élégance parisienne et la tradition culinaire shanghaienne.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-098', 'Bleu Bao', 'restaurant', 'chinois / tea house', '8 Rue Saint-Lazare', '', 'Bleu Bao est la version raffinée et esthète de la Bao Family. Installé rue Saint-Lazare, cet établissement rend hommage aux maisons de thé traditionnelles chinoises avec un décor bleu azur et une porcelaine délicate. L''atmosphère y est plus feutrée et sereine que dans les autres adresses du groupe, idéale pour un déjeuner chic ou un dîner intimiste. Outre les excellents dim-sums et baos, le lieu propose une sélection de thés d''exception et des cocktails inspirés de l''Asie. C''est le mariage parfait entre l''élégance parisienne et la tradition culinaire shanghaienne.');
INSERT INTO places VALUES ('poi-103', 'Buvette Paris', 'buvette-paris', 'restaurant', 'gastrothèque', 'culturel', 48.88044, 2.337737, 9, '28 Rue Henry Monnier', '#c499ff', 'pin', 1, 4.3, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1jo_MDNAQitsz1BKuKSVUqfwRlj_ymqByKgeFPdPPxck4DpEh9CLIUPz8-zXq3rQW5UBwjkIdiPUUXnAirIZKRKFnQMGrX8Z-Qsz9PNQE2ThFMGEWBipWaUa3Zrdi9e20WVUaW4KvDfD_iSoq405iXoyOaiPn7uavSkylKaefLfosY0YP1x3eegdt52niH9XnFWV3CWMAxi_W7N7SSNmQYUDHUFePirDJGTb1O0kO5i3w8RE-z_STPiJsHiFJpMjgZSYxE-8laZCKC-pmvlRajmSc1uABJ09PKNzTOeTE0JxtvAflEfgHnI_d5lxfnhaOQ8wu59Sdf28NJSW9-R3v2xMMHIcZinFDvZDj2n4FzLmemxZOM00Gay-UjAQ8ppoF-3wLVYw32Z_i3Ir71O8-oAF1X2LGJFsN9KqvGEJr62g&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 16, 0, '€', NULL, NULL, NULL, 3.5, 16, 50, '{"chill":4.8,"festif":9.3,"culturel":25}', '{}', '["restaurant","gastrothèque"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":25,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3.5,"dish_price":16,"budget_avg":16,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":16,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1jo_MDNAQitsz1BKuKSVUqfwRlj_ymqByKgeFPdPPxck4DpEh9CLIUPz8-zXq3rQW5UBwjkIdiPUUXnAirIZKRKFnQMGrX8Z-Qsz9PNQE2ThFMGEWBipWaUa3Zrdi9e20WVUaW4KvDfD_iSoq405iXoyOaiPn7uavSkylKaefLfosY0YP1x3eegdt52niH9XnFWV3CWMAxi_W7N7SSNmQYUDHUFePirDJGTb1O0kO5i3w8RE-z_STPiJsHiFJpMjgZSYxE-8laZCKC-pmvlRajmSc1uABJ09PKNzTOeTE0JxtvAflEfgHnI_d5lxfnhaOQ8wu59Sdf28NJSW9-R3v2xMMHIcZinFDvZDj2n4FzLmemxZOM00Gay-UjAQ8ppoF-3wLVYw32Z_i3Ir71O8-oAF1X2LGJFsN9KqvGEJr62g&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Importé du West Village par Jody Williams, Buvette Paris est devenu en quelques années une véritable institution de South Pigalle. Plus qu''un restaurant, c''est une ''gastrothèque'' ouverte du matin au soir où l''on se presse pour un café, un déjeuner sur le pouce ou un dîner qui s''éternise. Le décor – briques apparentes, immense comptoir en zinc, lumière tamisée – est tout simplement irrésistible. On y déguste des classiques français en portions réduites (œuf mouillette, coq au vin, tarte Tatin) avec une précision de bistrot new-yorkais. C''est serré, c''est animé, c''est chic : c''est le Paris dont on ne se lasse jamais.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-103', 'Buvette Paris', 'restaurant', 'gastrothèque', '28 Rue Henry Monnier', '', 'Importé du West Village par Jody Williams, Buvette Paris est devenu en quelques années une véritable institution de South Pigalle. Plus qu''un restaurant, c''est une ''gastrothèque'' ouverte du matin au soir où l''on se presse pour un café, un déjeuner sur le pouce ou un dîner qui s''éternise. Le décor – briques apparentes, immense comptoir en zinc, lumière tamisée – est tout simplement irrésistible. On y déguste des classiques français en portions réduites (œuf mouillette, coq au vin, tarte Tatin) avec une précision de bistrot new-yorkais. C''est serré, c''est animé, c''est chic : c''est le Paris dont on ne se lasse jamais.');
