L, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Gros Bao est le navire amiral de la Bao Family sur le Canal Saint-Martin. Sa façade rouge flamboyante est devenue un repère incontournable. Dans une ambiance de cantine hong-kongaise moderne et survitaminée, on y déguste des baos format XXL, des nouilles sautées au wok et un canard laqué réputé. La salle à l''étage offre une vue imprenable sur le canal, rendant l''expérience aussi visuelle que gustative. C''est bruyant, convivial, généreux et c''est sans doute l''un des lieux les plus Instagrammables et énergiques de l''Est parisien.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-096', 'Gros Bao', 'restaurant', 'chinois / bao', '72 Quai de Jemmapes', '', 'Gros Bao est le navire amiral de la Bao Family sur le Canal Saint-Martin. Sa façade rouge flamboyante est devenue un repère incontournable. Dans une ambiance de cantine hong-kongaise moderne et survitaminée, on y déguste des baos format XXL, des nouilles sautées au wok et un canard laqué réputé. La salle à l''étage offre une vue imprenable sur le canal, rendant l''expérience aussi visuelle que gustative. C''est bruyant, convivial, généreux et c''est sans doute l''un des lieux les plus Instagrammables et énergiques de l''Est parisien.');
