INSERT INTO places VALUES ('poi-094', 'Le Syndicat', 'le-syndicat', 'bar', 'craft cocktails', 'festif', 48.871864, 2.35365, 10, '51 Rue du Faubourg Saint-Denis', '#ffab60', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2OJ1NNxktATymgRtyf00bIEYcXLb_XxmM6piMb2uomG7fk5CuLNO3-NiemaMjMcxcXe2ecZ7B6aVxIAsbLcU__ncS6zgGgI9lrq6HT04DaTCl3kctlBFc52fKt4hFZQccXR6pQmBC8MyT-4ruoyUxViU86ltNZCDUy7xDBCNFpDssYpifRJ36rK93EqrQOOnjqLwyWtk_XqBH9f6PNniFy8fgUh8ojj_xN54aiDH-kMDYCJ6A4YoD3iBYtipS6dK0l-DEsFmCy25BMDKnuTZuqDCI2cw14fZYhf9LlvyI&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 0, 0, '€', NULL, 15, NULL, 0, 33, 50, '{"chill":3.8,"festif":25,"culturel":8}', '{}', '["bar","craft cocktails"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":33,"is_free":false,"pint_price":0,"cocktail_price":15,"coffee_price":0,"dish_price":33,"last_updated":"2025-01-15","budget_avg":0,"type":"bar","menu_items":[],"_debug_manual_dish_price":33,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2OJ1NNxktATymgRtyf00bIEYcXLb_XxmM6piMb2uomG7fk5CuLNO3-NiemaMjMcxcXe2ecZ7B6aVxIAsbLcU__ncS6zgGgI9lrq6HT04DaTCl3kctlBFc52fKt4hFZQccXR6pQmBC8MyT-4ruoyUxViU86ltNZCDUy7xDBCNFpDssYpifRJ36rK93EqrQOOnjqLwyWtk_XqBH9f6PNniFy8fgUh8ojj_xN54aiDH-kMDYCJ6A4YoD3iBYtipS6dK0l-DEsFmCy25BMDKnuTZuqDCI2cw14fZYhf9LlvyI&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Caché derrière une façade d''immeuble décatie recouverte d''affiches sauvages, Le Syndicat est en réalité l''une des tables les plus influentes de la mixology mondiale. Sa mission est d''une clarté totale : défendre et glorifier les spiritueux français. Ici, pas de whisky écossais ni d''alcools internationaux ; tout, du Cognac à l''absinthe, est sourcé dans l''Hexagone. Le décor ''schlague-chic'', avec ses tentures dorées et son éclairage tamisé, vibre au son d''une playlist hip-hop pointue. C''est électrique, audacieux, et parfaitement révélateur de l''esprit du Faubourg Saint-Denis.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-094', 'Le Syndicat', 'bar', 'craft cocktails', '51 Rue du Faubourg Saint-Denis', '', 'Caché derrière une façade d''immeuble décatie recouverte d''affiches sauvages, Le Syndicat est en réalité l''une des tables les plus influentes de la mixology mondiale. Sa mission est d''une clarté totale : défendre et glorifier les spiritueux français. Ici, pas de whisky écossais ni d''alcools internationaux ; tout, du Cognac à l''absinthe, est sourcé dans l''Hexagone. Le décor ''schlague-chic'', avec ses tentures dorées et son éclairage tamisé, vibre au son d''une playlist hip-hop pointue. C''est électrique, audacieux, et parfaitement révélateur de l''esprit du Faubourg Saint-Denis.');
INSERT INTO places VALUES ('poi-021', 'Chez Jeannette', 'chez-jeannette', 'bar', 'bar-retro', 'chill', 48.87169, 2.353509, 10, '47 Rue du Faubourg Saint-Denis', '#8ccaf7', 'pin', 1, 4.1, 0, 'https://images.unsplash.com/photo-1514933651103-005eec06c04b?auto=format&fit=crop&q=80&w=1000', NULL, 6.5, 0, '€', 6.5, NULL, NULL, 0, 9, 50, '{"chill":22,"festif":18,"culturel":12}', '{}', '["bar","bar-retro"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":6.5,"cocktail_price":0,"coffee_price":0,"dish_price":9,"last_updated":"2025-01-15","budget_avg":6.5,"type":"bar","menu_items":[],"_debug_manual_dish_price":9,"_debug_median_dish_price":null}', '{"hero":"https://images.unsplash.com/photo-1514933651103-005eec06c04b?auto=format&fit=crop&q=80&w=1000","gallery":[]}', '[]', NULL, '{"insider_tip":"Les tables tout au fond à gauche sont parfaites pour observer le ballet du bar sans être bousculé.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Porte d''entrée historique du renouveau de la rue du Faubourg Saint-Denis, Chez Jeannette est passé du statut de troquet de quartier à celui de QG incontournable pour toute une génération. Son décor de brasserie 1900 fatiquée et son ambiance électrique en font un lieu de vie permanent, du premier café au dernier digestif.', 'Les tables tout au fond à gauche sont parfaites pour observer le ballet du bar sans être bousculé.', 'Château d''Eau', '[4]', '[]', NULL);
