INSERT INTO places VALUES ('poi-013', 'Café A', 'cafe-a', 'café', 'cafe-jardin', 'chill', 48.875386, 2.360012, 10, '148 Rue du Faubourg Saint-Martin', '#8ccaf7', 'pin', 1, 4.2, 0, 'https://upload.wikimedia.org/wikipedia/commons/c/c9/Jardin_Villemin_-_Couvent_des_R%C3%A9collets.jpg', NULL, 3.5, 0, '€', NULL, NULL, NULL, 3.5, 16, 50, '{"chill":24,"festif":4,"culturel":7.5}', '{}', '["café","cafe-jardin"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":20,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3.5,"dish_price":16,"last_updated":"2025-01-15","budget_avg":3.5,"type":"cafe","menu_items":[],"_debug_manual_dish_price":16,"_debug_median_dish_price":null}', '{"hero":"https://upload.wikimedia.org/wikipedia/commons/c/c9/Jardin_Villemin_-_Couvent_des_R%C3%A9collets.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Installé dans l''ancien couvent des Récollets (actuelle Maison de l''Architecture), près de la Gare de l''Est, le Café A possède l''une des plus belles cours intérieures secrètes de Paris. On boit un verre sous les arcades ou allongé dans des transats sur le gravier blanc, à l''ombre de vieux arbres. C''est calme, vaste, et inattendu dans ce quartier dense. Un havre de paix architectural parfait pour les beaux jours.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'Gare de l''Est', '[4,5,7]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-013', 'Café A', 'café', 'cafe-jardin', '148 Rue du Faubourg Saint-Martin', '', 'Installé dans l''ancien couvent des Récollets (actuelle Maison de l''Architecture), près de la Gare de l''Est, le Café A possède l''une des plus belles cours intérieures secrètes de Paris. On boit un verre sous les arcades ou allongé dans des transats sur le gravier blanc, à l''ombre de vieux arbres. C''est calme, vaste, et inattendu dans ce quartier dense. Un havre de paix architectural parfait pour les beaux jours.');
INSERT INTO places VALUES ('poi-030', 'Tête dans les Olives', 'tete-dans-olives', 'restaurant', 'epicerie-bar', 'chill', 48.873408, 2.37073, 10, '2 Rue Sainte-Marthe', '#8ccaf7', 'pin', 1, 4.7, 0, '/images/tete-olives.jpg', NULL, 30, 0, '€', NULL, NULL, NULL, 4.5, 30, 50, '{"chill":24,"festif":5,"culturel":7.5}', '{}', '["restaurant","epicerie-bar"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":4.5,"dish_price":30,"last_updated":"2025-01-15","budget_avg":30,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":30,"_debug_median_dish_price":null}', '{"hero":"/images/tete-olives.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Table d''hôte unique (5 pers max). Cuisine sicilienne authentique.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Une table d''hôtes clandestine cachée dans une épicerie sicilienne minuscule. Cédric Casanova, le propriétaire, source ses huiles d''olive et ses produits directement chez les petits producteurs en Sicile. Le soir, sur réservation uniquement (et c''est souvent complet des mois à l''avance), la boutique se transforme en salle à manger pour un groupe privé (max 6-8 personnes). On y déguste un festin de produits bruts exceptionnels arrosés de vin naturel. C''est l''expérience gastronomique la plus intime et authentique de Paris.', 'Table d''hôte unique (5 pers max). Cuisine sicilienne authentique.', 'Goncourt', '[11]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-030', 'Tête dans les Olives', 'restaurant', 'epicerie-bar', '2 Rue Sainte-Marthe', '', 'Une table d''hôtes clandestine cachée dans une épicerie sicilienne minuscule. Cédric Casanova, le propriétaire, source ses huiles d''olive et ses produits directement chez les petits producteurs en Sicile. Le soir, sur réservation uniquement (et c''est souvent complet des mois à l''avance), la boutique se transforme en salle à manger pour un groupe privé (max 6-8 personnes). On y déguste un festin de produits bruts exceptionnels arrosés de vin naturel. C''est l''expérience gastronomique la plus intime et authentique de Paris.');
