INSERT INTO places_fts VALUES ('poi-052', 'Bambino', 'bar', 'bar-a-vinyles', '25 Rue Saint-Sébastien', '', 'Inspiré des bars d''écoute (kissa) japonais, Bambino est un lieu où la musique est le cœur battant. Les murs tapissés de vinyles et le sound-system vintage hi-fi créent une acoustique exceptionnelle. On y dîne de petites assiettes fusion (Japon/Méditerranée), on y boit du vin nature et on profite d''une programmation pointue uniquement sur platines.');
