INSERT INTO places_fts VALUES ('poi-brasserie-rosie', 'Brasserie Rosie', 'restaurant', 'brasserie traditionnel restaurant', '53 Rue du Faubourg Saint-Antoine', '', 'Une brasserie furieusement moderne qui ressuscite l''âme des grands bouillons parisiens avec un décor hyper travaillé (moquettes fleuries, banquettes velours rose) et un 100% fait main à prix justes.');
INSERT INTO places VALUES ('poi-037', 'L''Arbre à Café - Oberkampf', 'caf-oberkampf', 'café', 'coffee-shop', 'chill', 48.864792, 2.372771, 11, '61 Rue Oberkampf', '#8ccaf7', 'pin', 1, 4.6, 0, 'https://images.unsplash.com/photo-1555396273-367ea4eb4db5?auto=format&fit=crop&w=1000&q=80', NULL, 3, 0, '€', 8, NULL, NULL, 3, 0, 50, '{"chill":24,"festif":2,"culturel":2}', '{}', '["café","coffee-shop"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":8,"cocktail_price":0,"coffee_price":3,"dish_price":0,"budget_avg":3,"type":"cafe","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://images.unsplash.com/photo-1555396273-367ea4eb4db5?auto=format&fit=crop&w=1000&q=80","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez absolument ou préparez-vous à boire un pastis au comptoir pendant 1h.","specials":{"cuisine":[],"drinks":["Café"]}}', 'Hippolyte Courty, sourcer de café pour les plus grands chefs (Pierre Hermé, Alain Ducasse), a ouvert ici son école et son atelier. C''est le lieu pour comprendre que le café est un produit de terroir complexe, comme le vin. On y déguste des variétés rares, fermentées avec soin, préparées en filtre ou espresso avec une précision scientifique. Le décor est épuré pour laisser toute la place à la dégustation aromatique. Une expérience puriste.', 'Réservez absolument ou préparez-vous à boire un pastis au comptoir pendant 1h.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-037', 'L''Arbre à Café - Oberkampf', 'café', 'coffee-shop', '61 Rue Oberkampf', '', 'Hippolyte Courty, sourcer de café pour les plus grands chefs (Pierre Hermé, Alain Ducasse), a ouvert ici son école et son atelier. C''est le lieu pour comprendre que le café est un produit de terroir complexe, comme le vin. On y déguste des variétés rares, fermentées avec soin, préparées en filtre ou espresso avec une précision scientifique. Le décor est épuré pour laisser toute la place à la dégustation aromatique. Une expérience puriste.');
