INSERT INTO places VALUES ('poi-108', 'Double Dragon', 'double-dragon', 'restaurant', 'fusion asiatique', 'festif', 48.862601, 2.379892, 11, '52 Rue Saint-Maur', '#ffab60', 'pin', 1, 4.2, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN24VLLsEyqXc8oEPgqRfajO_nKS8FLRNZkwe2ahMnV7dKQeeHV-256A0cLvMM6Dd4irL3Hiv7-o3NUsdu4UGbTM0wP6l7-UNbwRMzrQinWHt6DifnDa2FauBBa_m6mwy843XyE4OM_k8jcLfrKZIzHWYp5KnODgSTjL8BohDkKDw0FWNVCnNFjD61GD4b6XvR0exgNSP78lUtGPoyGEj0R1N20BxjrrYDNXt4WoYWOoBGu-pBwKZXQMSI2F-Epv1nO3lAeySq1zUHiQQ3BPZQfBUuQR3g19dfb1TJBE5bhoe5uEAybhLoC04YSN9fBxziyfRJoRRdNGVzg8yezTCxifKBSF18dKvyK6WsUboiTIWhW_2_i4MCsFPgtQA1JsvUGUrKyArxfO5kk8XrPeiD227kIcFjbXSXvYR3VcTXL6Tg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 11, 0, '€', NULL, NULL, NULL, 0, 11, 50, '{"chill":5.6,"festif":25,"culturel":8}', '{}', '["restaurant","fusion asiatique"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":11,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":11,"budget_avg":11,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":11,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN24VLLsEyqXc8oEPgqRfajO_nKS8FLRNZkwe2ahMnV7dKQeeHV-256A0cLvMM6Dd4irL3Hiv7-o3NUsdu4UGbTM0wP6l7-UNbwRMzrQinWHt6DifnDa2FauBBa_m6mwy843XyE4OM_k8jcLfrKZIzHWYp5KnODgSTjL8BohDkKDw0FWNVCnNFjD61GD4b6XvR0exgNSP78lUtGPoyGEj0R1N20BxjrrYDNXt4WoYWOoBGu-pBwKZXQMSI2F-Epv1nO3lAeySq1zUHiQQ3BPZQfBUuQR3g19dfb1TJBE5bhoe5uEAybhLoC04YSN9fBxziyfRJoRRdNGVzg8yezTCxifKBSF18dKvyK6WsUboiTIWhW_2_i4MCsFPgtQA1JsvUGUrKyArxfO5kk8XrPeiD227kIcFjbXSXvYR3VcTXL6Tg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Double Dragon est l''antenne festive et pimentée des sœurs Levha dans le 11ème. Le concept ? Une cuisine fusion asiatique (Philippines, Chine, Thaïlande) passée à la moulinette de l''insolence française. On y dévore des bao au Comté fondu, du ''KFC'' (Korean Fried Chicken) ultra-croustillant et des travers de porc au miel sous des néons colorés. L''ambiance est bruyante, pop et terriblement cool. On y boit des vins naturels qui calment le feu du piment, dans une salle qui ne désemplit jamais de la jeunesse dorée du quartier. C''est piquant, c''est joyeux et c''est terriblement addictif.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-108', 'Double Dragon', 'restaurant', 'fusion asiatique', '52 Rue Saint-Maur', '', 'Double Dragon est l''antenne festive et pimentée des sœurs Levha dans le 11ème. Le concept ? Une cuisine fusion asiatique (Philippines, Chine, Thaïlande) passée à la moulinette de l''insolence française. On y dévore des bao au Comté fondu, du ''KFC'' (Korean Fried Chicken) ultra-croustillant et des travers de porc au miel sous des néons colorés. L''ambiance est bruyante, pop et terriblement cool. On y boit des vins naturels qui calment le feu du piment, dans une salle qui ne désemplit jamais de la jeunesse dorée du quartier. C''est piquant, c''est joyeux et c''est terriblement addictif.');
