aps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfVJCLnDQ6CPxRMH4buEGha_MVkuU8torvc1KWP4VJeK3aDCtDGkRLsmdaTPTTBR00DVN9aHBBJLeNFDuxRsPU0yGwjr82JhTYERAofIMgjr8iy-3m3Vw1sgGg5OxIuvfldZxXVwEtZmPobJrhhPU_PdWxW3luYCBgY3CZaQ0BIXDDMKHTMKvR2wip3H64l2y3kwN0qWr5XkZRMYo2Rrup-esRamua9BRxBe6zGKo8OfYCI433UhSmEBppfad0US_YdgTgy1EooLfrP-Wvo8HRV5Z8WIP_qS4rAQ92HWoqVivA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"• Une institution discrète parfaite pour un très bon date avec l''Italie dans l''assiette.\n• Réservez au moins deux semaines à l''avance, la salle complète à chaque service.\n• Ne partez pas sans tester le Cannolo sicilien ultra croustillant.","specials":{"cuisine":["Mezzi paccheri langoustines","Cannolo Sicilien","Vitello Tonnato"],"drinks":["Barolo","Vins naturels italiens"],"must_eat":"La précision est la de mise. Les pâtes sont al dente et baignent dans des justes parfaits, à l''image des Mezzi paccheri aux langoustines crues. Du brutal chic.","must_drink":"Magnifique cave italienne, beaucoup de belles quilles nord-italiennes."},"expert_catchline":"Trattoria bourgeoise de très haute volée, pour manger les meilleures pâtes de Paris dans le calme absolu."}', 'Derrière sa devanture boisée, l''Osteria Ferrara cache la quintessence de la trattoria chic. Le chef Fabrizio Ferrara y dépoussière la gastronomie italienne avec un amour pur du produit brut. Loin du vacarme festif d''autres trattorias parisiennes, on vient ici se murmurer des secrets devant une Calamarata incandescente et un verre de vin pointu.', '• Une institution discrète parfaite pour un très bon date avec l''Italie dans l''assiette.
INSERT INTO places_fts VALUES ('poi-osteria-ferrara', 'Osteria Ferrara', 'restaurant', 'italien pâtes convivial bistronomique', '7 Rue du Dahomey', '', 'Derrière sa devanture boisée, l''Osteria Ferrara cache la quintessence de la trattoria chic. Le chef Fabrizio Ferrara y dépoussière la gastronomie italienne avec un amour pur du produit brut. Loin du vacarme festif d''autres trattorias parisiennes, on vient ici se murmurer des secrets devant une Calamarata incandescente et un verre de vin pointu.');
INSERT INTO places VALUES ('poi-066', 'Le Perchoir Ménilmontant', 'le-perchoir-menilmontant', 'bar', 'rooftop', 'festif', 48.865372, 2.381822, 11, '14 Rue Crespin du Gast', '#ffab60', 'pin', 1, 4.1, 0, 'https://images.unsplash.com/photo-1533174072545-7a4b6ad7a6c3?q=80&w=2070&auto=format&fit=crop', NULL, 8, 0, '€', 8, 15, NULL, 0, 16, 50, '{"chill":8,"festif":23.5,"culturel":5}', '{}', '["bar","rooftop"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":8,"cocktail_price":15,"coffee_price":0,"dish_price":16,"budget_avg":8,"type":"bar","menu_items":[],"_debug_manual_dish_price":16,"_debug_median_dish_price":null}', '{"hero":"https://images.unsplash.com/photo-1533174072545-7a4b6ad7a6c3?q=80&w=2070&auto=format&fit=crop","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est au fond de la cour, ne vous fiez pas à l''aspect industriel du bâtiment.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Premier-né de la famille des Perchoirs en 2013, ce rooftop a révolutionné la vie nocturne parisienne en ouvrant les toits de l''Est parisien au public. Perché au 7ème étage d''un immeuble industriel de la rue Crespin du Gast, on y accède par un ascenseur discret, presque secret. Une fois en haut, la magie opère : une terrasse de 400m² à la décoration bohème-chic (bois brut, coussins colorés, plantes verdoyantes) offre une vue spectaculaire à 360 degrés sur les toits de Paris et le Sacré-Cœur. Fondé par Adrien Boissaye avec l''envie d''insuffler un air de vacances permanent à la capitale, Le Perchoir est devenu le repaire de la jeunesse créative parisienne. On y vient pour voir le coucher du soleil avec un cocktail signature, avant que l''ambiance ne s''électrise à la tombée de la nuit sous les guirlandes lumineuses. Un véritable observatoire urbain où le temps semble s''arrêter au-dessus du tumulte de Ménilmontant.', 'L''entrée est au fond de la cour, ne vous fiez pas à l''aspect industriel du bâtiment.', 'Ménilmontant', '[2]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-066', 'Le Perchoir Ménilmontant', 'bar', 'rooftop', '14 Rue Crespin du Gast', '', 'Premier-né de la famille des Perchoirs en 2013, ce rooftop a révolutionné la vie nocturne parisienne en ouvrant les toits de l''Est parisien au public. Perché au 7ème étage d''un immeuble industriel de la rue Crespin du Gast, on y accède par un ascenseur discret, presque secret. Une fois en haut, la magie opère : une terrasse de 400m² à la décoration bohème-chic (bois brut, coussins colorés, plantes verdoyantes) offre une vue spectaculaire à 360 degrés sur les toits de Paris et le Sacré-Cœur. Fondé par Adrien Boissaye avec l''envie d''insuffler un air de vacances permanent à la capitale, Le Perchoir est devenu le repaire de la jeunesse créative parisienne. On y vient pour voir le coucher du soleil avec un cocktail signature, avant que l''ambiance ne s''électrise à la tombée de la nuit sous les guirlandes lumineuses. Un véritable observatoire urbain où le temps semble s''arrêter au-dessus du tumulte de Ménilmontant.');
