eapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfUsgCtPYHnDcgErkH9zVwXKeMrtBw5VBFG1ZlzJngqO6AW2j0zlSSKcCLNDMkZ8yncBgs1vD8fJR6DMosdd3DoYwSUYtZFAGVZz46Ih_WBPGM2ODHkLXuYcyXy74J35TTBbNQsEZ4I9BBE2ixb05ySBG5aquFhZfoF7jidpoiX-ucMgt__N77qvcLNhybM8auTX90YljA8UBglSG_WNyVPA0tGA15KwrGmDiWX5LW8nx73Bc2N0HnogjAxrBt3Xk8kuRoapanAuhdB1kq8kF66yfUXUTy6pynHiARFqfR0&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"• Un temple du vin nature : laissez-vous guider les yeux fermés par les sommeliers.\n• Attention, le budget pour un dîner complet avec vin tape vite très haut (compter 70-80€/pers).\n• Les créations végétales dépassent souvent les viandes en ingéniosité.","specials":{"cuisine":["Maigre au barbecue","Tortellini Châtaigne","Tarta de Queso"],"drinks":["Pétillant Naturel","Vins oranges","Cidres pointus"],"must_eat":"La rôtisse et le barbecue au charbon parfument subtilement les viandes et poissons (Maigre à 34€). Gardez de la place pour la cultissime Tarta de Queso au caramel.","must_drink":"Une impressionnante bible de vins naturels, sourcée avec maniaquerie."},"expert_catchline":"Néobistrot percutant et cave naturiste vertigineuse. Le QG des palais affutés du 11e."}', 'Derrière une ancienne façade vitrée classée, Le Saint Sébastien joue la carte du bistronomique ultra-pointu et légumier. L''assiette, très moderne et axée sur une technique de feu poussée (barbecue japonais), se marie à l''une des caves à vins naturels les plus épaisses du quartier. Un repaire pour gastronomes avertis.', '• Un temple du vin nature : laissez-vous guider les yeux fermés par les sommeliers.
INSERT INTO places_fts VALUES ('poi-le-saint-sebastien', 'Le Saint Sébastien', 'restaurant', 'bistronomique vins natures végétal de saison', '42 Rue Saint-Sébastien', '', 'Derrière une ancienne façade vitrée classée, Le Saint Sébastien joue la carte du bistronomique ultra-pointu et légumier. L''assiette, très moderne et axée sur une technique de feu poussée (barbecue japonais), se marie à l''une des caves à vins naturels les plus épaisses du quartier. Un repaire pour gastronomes avertis.');
INSERT INTO places VALUES ('poi-227', 'Dirty Lemon', 'dirty-lemon', 'bar', 'bar-a-cocktail', 'chill', 48.862719, 2.373462, 11, '24 Rue de la Folie Méricourt', '#8ccaf7', 'pin', 1, 4.8, 0, 'https://images.unsplash.com/photo-1514933651103-005eec06c04b?auto=format&fit=crop&q=80&w=1000', NULL, 0, 0, '€', NULL, 13, NULL, 0, 0, 50, '{"chill":15,"festif":12,"culturel":8}', '{}', '["bar","bar-a-cocktail"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":25,"is_free":false,"pint_price":0,"cocktail_price":13,"coffee_price":0,"dish_price":0,"budget_avg":0,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://images.unsplash.com/photo-1514933651103-005eec06c04b?auto=format&fit=crop&q=80&w=1000","gallery":[]}', '[]', NULL, '{"insider_tip":"La carte des shots est aussi travaillée que celle des long-drinks.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Dirty Lemon est un bar à cocktails vibrant et inclusif qui apporte une touche de fraîcheur et d''audace à la scène parisienne. Fondé par une équipe de femmes talentueuses, le lieu se définit par une énergie communicative, un décor acidulé et une carte de cocktails qui ne craint pas de bousculer les conventions. Ici, les saveurs sont vives, souvent citronnées ou herbacées, privilégiant les produits frais et les combinaisons inattendues. Que ce soit pour un apéro entre amis ou une soirée plus festive, Dirty Lemon s''est imposé comme un refuge chaleureux où la mixologie se veut accessible, créative et résolument moderne.', 'La carte des shots est aussi travaillée que celle des long-drinks.', 'Saint-Ambroise', '[9]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-227', 'Dirty Lemon', 'bar', 'bar-a-cocktail', '24 Rue de la Folie Méricourt', '', 'Dirty Lemon est un bar à cocktails vibrant et inclusif qui apporte une touche de fraîcheur et d''audace à la scène parisienne. Fondé par une équipe de femmes talentueuses, le lieu se définit par une énergie communicative, un décor acidulé et une carte de cocktails qui ne craint pas de bousculer les conventions. Ici, les saveurs sont vives, souvent citronnées ou herbacées, privilégiant les produits frais et les combinaisons inattendues. Que ce soit pour un apéro entre amis ou une soirée plus festive, Dirty Lemon s''est imposé comme un refuge chaleureux où la mixologie se veut accessible, créative et résolument moderne.');
INSERT INTO places VALUES ('poi-022', 'Atelier des Lumières', 'atelier-lumieres', 'museum', 'espace-culturel', 'culturel', 48.861615, 2.380813, 11, '38 Rue Saint-Maur', '#c499ff', 'pin', 1, 4.5, 0, '/images/atelier-lumieres.jpg', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":7.5,"festif":4,"culturel":24.5}', '{}', '["museum","espace-culturel"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":17,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":15,"type":"museum","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"/images/atelier-lumieres.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Expérience immersive sonore et visuelle. Réservez impérativement en ligne.","specials":{"cuisine":[],"drinks":[]}}', 'La première ''imprimerie numérique'' géante de Paris. Dans cette ancienne fonderie du XIXe siècle, les œuvres de Klimt, Van Gogh ou Dalí sont projetées en format XXL sur les murs de 10 mètres de haut et sur le sol, accompagnées d''une musique immersive. Ce n''est pas une exposition, c''est une plongée physique dans la peinture. On marche littéralement dans la couleur. C''est l''expérience artistique idéale pour ceux qui trouvent les musées classiques trop statiques.', 'Expérience immersive sonore et visuelle. Réservez impérativement en ligne.', 'Voltaire', '[9]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-022', 'Atelier des Lumières', 'museum', 'espace-culturel', '38 Rue Saint-Maur', '', 'La première ''imprimerie numérique'' géante de Paris. Dans cette ancienne fonderie du XIXe siècle, les œuvres de Klimt, Van Gogh ou Dalí sont projetées en format XXL sur les murs de 10 mètres de haut et sur le sol, accompagnées d''une musique immersive. Ce n''est pas une exposition, c''est une plongée physique dans la peinture. On marche littéralement dans la couleur. C''est l''expérience artistique idéale pour ceux qui trouvent les musées classiques trop statiques.');
