TwFyPss5wy-Xu4SXZr7ONjA74AHNejd5XSqvK4ajaygG_dLZr3XTGQl0XVYJpkhK2PlVGtf4Tpwjr4jhdcr_v5ZKZbbziSPUf31ChUyMRhD1osxc4I2QKddqQFZ3XPUDW9uXAoJFaLCm_DMT6B1jPD1OLSA-nhGPr-f2OO5aoo&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"• Merveilleuse cave à vins natures, n''hésitez pas à demander conseil à l''équipe, experte en ''jus vivants''.\n• L''ambiance monte d''un cran au fil de la soirée, avec une bande-son souvent très cool (hip-hop/soul), parfait pour les petits groupes.\n• Le menu change extrêmement souvent, ne vous fiez jamais à ce que vous lisez sur internet la veille.","specials":{"cuisine":["Bistronomie créative et changeante","Assiettes à partager umami"],"drinks":["Sélection pointue de vins natures et biodynamiques"],"must_eat":"Faites confiance à l''inspiration du jour : Gianmarco Gorni a une maîtrise folle des assaisonnements et des jus corsés.","must_drink":"Laissez-les vous faire goûter à l''aveugle un vin orange un peu fou."},"expert_catchline":"Néo-bistrot canaille et vins natures par le très créatif chef Gianmarco Gorni."}', 'Derrière sa discrète devanture de la rue Amelot, Goguette (mené par le chef Gianmarco Gorni, vu dans Top Chef) envoie une bistronomie délurée et percutante. Le soir, on y partage des assiettes canailles et créatives (souvent très riches en umami) au comptoir ou sur les tables hautes, en éclusant des quilles de vin nature.', '• Merveilleuse cave à vins natures, n''hésitez pas à demander conseil à l''équipe, experte en ''jus vivants''.
INSERT INTO places_fts VALUES ('poi-goguette', 'Goguette', 'restaurant', 'bistronomique cave à manger bar à vins restaurant', '108 Rue Amelot', '', 'Derrière sa discrète devanture de la rue Amelot, Goguette (mené par le chef Gianmarco Gorni, vu dans Top Chef) envoie une bistronomie délurée et percutante. Le soir, on y partage des assiettes canailles et créatives (souvent très riches en umami) au comptoir ou sur les tables hautes, en éclusant des quilles de vin nature.');
