INSERT INTO places_fts VALUES ('poi-chanceux', 'Chanceux', 'restaurant', 'bistronomie tapas brunch restaurant', '57 Rue Saint-Maur', '', 'Une petite merveille de quartier hybride sur la rue Saint-Maur : épicerie, coffee shop le matin (merveilleux granola), cantine bistronomique le midi (avec ses fameux melts) et bar à tapas à prix doux en fin de semaine. La comfort food est ici élevée au rang d''art du quotidien.');
