INSERT INTO places VALUES ('poi-154', 'Chez Gladines', 'chez-gladines-butte', 'restaurant', 'basque', 'chill', 48.828804, 2.3506, 13, '30 Rue des Cinq Diamants', '#8ccaf7', 'pin', 1, 4.4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1KfDpbME2aXHBULXebajqcekiaH6LlW9Sl-dwGUuB76tLXExGaw5mkiTOC9Q8jDxm1TSr6YcLNMS8sHM1vfjZC-Eb9FBU1ZUGUqZJ_V3-HFVnlyIu2hD-Upy89_R-vBIGpwLQw0POSQXZ4PCJ9dUqsomEt_reE42onYBjh1IqxAT6-U9SuI2fmNmZDQikFDIe-s8ANtJbtyRuNJkZuQu4PHYVBCyYVyCZqwcrUi6lXZGkrMeau3Y2cJ9Ur3WrCLjQf5Hp9EeqChJt1RqchnE5cti8s_QRArVD9IvoOa9VJbg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 98, 0, '€', NULL, NULL, NULL, 0, 98, 50, '{"chill":21,"festif":4,"culturel":5}', '{}', '["restaurant","basque"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":98,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":98,"budget_avg":98,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":98,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1KfDpbME2aXHBULXebajqcekiaH6LlW9Sl-dwGUuB76tLXExGaw5mkiTOC9Q8jDxm1TSr6YcLNMS8sHM1vfjZC-Eb9FBU1ZUGUqZJ_V3-HFVnlyIu2hD-Upy89_R-vBIGpwLQw0POSQXZ4PCJ9dUqsomEt_reE42onYBjh1IqxAT6-U9SuI2fmNmZDQikFDIe-s8ANtJbtyRuNJkZuQu4PHYVBCyYVyCZqwcrUi6lXZGkrMeau3Y2cJ9Ur3WrCLjQf5Hp9EeqChJt1RqchnE5cti8s_QRArVD9IvoOa9VJbg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Chez Gladines à la Butte-aux-Cailles, c''est l''assurance d''un repas gargantuesque et joyeux. Cette institution de la cuisine basque ne dépareille jamais : salades qui débordent de l''assiette, magret de canard juteux et pommes de terre sautées mythiques. L''ambiance est bruyante, conviviale et les tables se touchent. C''est un lieu qui célèbre la vie, le piment d''Espelette et les grandes amitiés autour de carafes de vin de pays.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
