INSERT INTO places VALUES ('poi-169', 'Djoon', 'djoon', 'club', 'club-house', 'festif', 48.836567, 2.371439, 13, '22 Bd Vincent Auriol', '#ffab60', 'pin', 1, 3.7, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN05r-6JTJkai2OuvSfTr6v6ISTVgkAQNztikSc-yuSytjOo7ESH9ogyRfd49Ie1iXEqI1Oe8CkHca2fr1FMYuHGUFqoIrPWV01eUHLiuuxZsIn01hUqh_gN84Ghw_ezAyafRGASjoENL9WIlGbwZjbS2CbqVGP1PKXku0b7jJkM_3vKwsf9PwOcfTuny1TpG9I_Wd_K327eiVhPPGXDgE0Iy5lnovzLamtTCu11P_-CbELwhZWdptqpK-d_RRtbT5OT6NlPnOKPCxNjJnW65M9HrCp9c6pXjhbHhro3rf9ftA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 0, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["club","club-house"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":0,"type":"club","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN05r-6JTJkai2OuvSfTr6v6ISTVgkAQNztikSc-yuSytjOo7ESH9ogyRfd49Ie1iXEqI1Oe8CkHca2fr1FMYuHGUFqoIrPWV01eUHLiuuxZsIn01hUqh_gN84Ghw_ezAyafRGASjoENL9WIlGbwZjbS2CbqVGP1PKXku0b7jJkM_3vKwsf9PwOcfTuny1TpG9I_Wd_K327eiVhPPGXDgE0Iy5lnovzLamtTCu11P_-CbELwhZWdptqpK-d_RRtbT5OT6NlPnOKPCxNjJnW65M9HrCp9c6pXjhbHhro3rf9ftA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.","specials":{"cuisine":[],"drinks":[]}}', 'Le Djoon est le sanctuaire parisien de la house soulful et du disco. Sur deux niveaux dominant les quais de Seine, ce club à l''esprit new-yorkais attire les meilleurs danseurs de la capitale. Programmation afro-house, funky soul et sets pointus des résidents font vibrer le parquet sous les pieds d''un public connaisseur et ultra-bienveillant. Ici, on ne vient pas pour se montrer, mais pour se perdre dans le son et la danse jusqu au petit matin.', 'Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-169', 'Djoon', 'club', 'club-house', '22 Bd Vincent Auriol', '', 'Le Djoon est le sanctuaire parisien de la house soulful et du disco. Sur deux niveaux dominant les quais de Seine, ce club à l''esprit new-yorkais attire les meilleurs danseurs de la capitale. Programmation afro-house, funky soul et sets pointus des résidents font vibrer le parquet sous les pieds d''un public connaisseur et ultra-bienveillant. Ici, on ne vient pas pour se montrer, mais pour se perdre dans le son et la danse jusqu au petit matin.');
INSERT INTO places VALUES ('poi-153', 'La Folie en Tête', 'folie-en-tete', 'bar', 'bar-alternatif', 'festif', 48.82752, 2.348158, 13, '33 Rue de la Butte aux Cailles', '#ffab60', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN08SuQcBUT7UEjuM5lm--4G3DhMbQoKOpai1I2SViycHAWmTAVdYboX120db4arFGWB1KKkDqg-rnuO4VnYCMTbefXCp5N0XhXmNz2K_EoW5e20NW1NfSSHar-8_x2Pf2UWXqmDttj5wTxd7iuY2ea5EJrW5Btm0w-dyG0yYUGps-GIG1NzK3993gWG5KtzMM8waqJVRt-5PhWPVvSWW9mVLYjDLGFGpqw1rOd0tjjj3dOEMw_opYhrsYno0QccUx-93GkXC1Jrq4q_r0WF3W3P02EDHOzFlg5BKwy9afIcHA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 6, 0, '€', 6, NULL, NULL, 0, 0, 50, '{"chill":6,"festif":22,"culturel":5}', '{}', '["bar","bar-alternatif"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":6,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":6,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN08SuQcBUT7UEjuM5lm--4G3DhMbQoKOpai1I2SViycHAWmTAVdYboX120db4arFGWB1KKkDqg-rnuO4VnYCMTbefXCp5N0XhXmNz2K_EoW5e20NW1NfSSHar-8_x2Pf2UWXqmDttj5wTxd7iuY2ea5EJrW5Btm0w-dyG0yYUGps-GIG1NzK3993gWG5KtzMM8waqJVRt-5PhWPVvSWW9mVLYjDLGFGpqw1rOd0tjjj3dOEMw_opYhrsYno0QccUx-93GkXC1Jrq4q_r0WF3W3P02EDHOzFlg5BKwy9afIcHA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Bar associatif et solidaire, la Folie en Tête est l''une des dernières pépites authentiques du 13ème. Ambiance alter, concerts de jazz manouche impromptus et boissons à prix défiant toute concurrence. Le décor est fait de bric et de broc, créant une atmosphère de liberté absolue. C''est ici que bat le cœur de la Butte-aux-Cailles, entre deux débats sur le monde et un verre de vin rouge partagé.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-153', 'La Folie en Tête', 'bar', 'bar-alternatif', '33 Rue de la Butte aux Cailles', '', 'Bar associatif et solidaire, la Folie en Tête est l''une des dernières pépites authentiques du 13ème. Ambiance alter, concerts de jazz manouche impromptus et boissons à prix défiant toute concurrence. Le décor est fait de bric et de broc, créant une atmosphère de liberté absolue. C''est ici que bat le cœur de la Butte-aux-Cailles, entre deux débats sur le monde et un verre de vin rouge partagé.');
