'ambiance est celle d''un vrai caviste de quartier qui prend le temps de raconter chaque bouteille. Un refuge chaleureux et éclairé pour les amateurs de vins vivants sur les pentes de la Butte-aux-Cailles.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-155', 'Simone - La Cave Bio', 'bar', 'bar-a-vin', '13 Bd Arago', '', 'Cave à vins nature et biodynamiques tenue par des passionnés. Chez Simone, on découvre des pépites de vignerons qui respectent la terre, servies avec des planches de fromages et charcuteries de haute volée. L''ambiance est celle d''un vrai caviste de quartier qui prend le temps de raconter chaque bouteille. Un refuge chaleureux et éclairé pour les amateurs de vins vivants sur les pentes de la Butte-aux-Cailles.');
INSERT INTO places VALUES ('poi-151', 'Le Temps des Cerises', 'temps-des-cerises', 'bar', 'coopérative', 'festif', 48.82791, 2.350488, 13, '18-20 Rue de la Butte aux Cailles', '#ffab60', 'pin', 1, 4.4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2aJCn2Mm4W_IuStSMuLjANAFYhe1uSCZ1c7b7AHK4SS95p-g94HXCElbdvf7Vga_x6upnE38xTWW85TEXcVw11VZrY51ataiJia1D-wnlevU1zfTQL-lUgYqHLckhvw8AUEb_15PLLVTQrCGdyAxwbGdbK-LCsKQPgaQZtIvKrHvC4JDlP6WPDeItC4N5cemddi_q6itizp4z3bA6Hcjcbcb47NPbCERPdeYxr5Xpuo13OzmA9vPdXbEqfHyhdc2RMD8ZO5Q0ywAEF8FKcFarGjs_AVOE6juHzj_6S_zqG1A&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 5, 0, '€', 5, NULL, NULL, 0, 0, 50, '{"chill":6,"festif":22,"culturel":5}', '{}', '["bar","coopérative"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":6,"is_free":false,"pint_price":5,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":5,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2aJCn2Mm4W_IuStSMuLjANAFYhe1uSCZ1c7b7AHK4SS95p-g94HXCElbdvf7Vga_x6upnE38xTWW85TEXcVw11VZrY51ataiJia1D-wnlevU1zfTQL-lUgYqHLckhvw8AUEb_15PLLVTQrCGdyAxwbGdbK-LCsKQPgaQZtIvKrHvC4JDlP6WPDeItC4N5cemddi_q6itizp4z3bA6Hcjcbcb47NPbCERPdeYxr5Xpuo13OzmA9vPdXbEqfHyhdc2RMD8ZO5Q0ywAEF8FKcFarGjs_AVOE6juHzj_6S_zqG1A&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Le bar coopératif historique de la Butte-aux-Cailles. Géré par ses salariés depuis 1976, ce lieu incarne l''esprit rebelle et convivial du quartier. On y vient pour l''ambiance militante, les prix doux et les soirées qui s''enflamment au son de concerts acoustiques. C''est l''âme du 13ème populaire qui résiste, avec ses bières artisanales et son mélange social unique. Un refuge pour ceux qui cherchent la vérité de Paris loin des circuits formatés.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-151', 'Le Temps des Cerises', 'bar', 'coopérative', '18-20 Rue de la Butte aux Cailles', '', 'Le bar coopératif historique de la Butte-aux-Cailles. Géré par ses salariés depuis 1976, ce lieu incarne l''esprit rebelle et convivial du quartier. On y vient pour l''ambiance militante, les prix doux et les soirées qui s''enflamment au son de concerts acoustiques. C''est l''âme du 13ème populaire qui résiste, avec ses bières artisanales et son mélange social unique. Un refuge pour ceux qui cherchent la vérité de Paris loin des circuits formatés.');
