INSERT INTO places VALUES ('poi-005', 'Wanderlust', 'wanderlust', 'club', 'club-plein-air', 'festif', 48.840136, 2.370589, 13, '32 Quai d''Austerlitz', '#ffab60', 'pin', 1, 2.3, 0, 'https://upload.wikimedia.org/wikipedia/commons/5/5e/Cit%C3%A9_de_la_Mode_et_du_Design.jpg', NULL, 0, 0, '€', 9, NULL, NULL, 0, 15, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["club","club-plein-air"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":20,"is_free":false,"pint_price":9,"cocktail_price":0,"coffee_price":0,"dish_price":15,"budget_avg":0,"type":"club","menu_items":[],"_debug_manual_dish_price":15,"_debug_median_dish_price":null}', '{"hero":"https://upload.wikimedia.org/wikipedia/commons/5/5e/Cit%C3%A9_de_la_Mode_et_du_Design.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez avant 21h pour éviter la file interminable qui remonte sur le quai.","specials":{"cuisine":[],"drinks":[]}}', 'C''est la terrasse la plus vaste et la plus clubbing de la Cité de la Mode et du Design. Posée en bord de Seine avec sa structure verte reptilienne reconnaissable entre mille, Wanderlust est le temple de la fête estivale en plein air. On y danse sous les étoiles au son du hip-hop et du R&B, on boit des cocktails dans des verres en plastique (sécurité oblige) et on profite d''une vue dégagée sur le fleuve. Le public est jeune, la musique est forte, et l''ambiance est celle d''un spring break urbain chic.', 'Arrivez avant 21h pour éviter la file interminable qui remonte sur le quai.', 'Gare d''Austerlitz', '[5,10]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-005', 'Wanderlust', 'club', 'club-plein-air', '32 Quai d''Austerlitz', '', 'C''est la terrasse la plus vaste et la plus clubbing de la Cité de la Mode et du Design. Posée en bord de Seine avec sa structure verte reptilienne reconnaissable entre mille, Wanderlust est le temple de la fête estivale en plein air. On y danse sous les étoiles au son du hip-hop et du R&B, on boit des cocktails dans des verres en plastique (sécurité oblige) et on profite d''une vue dégagée sur le fleuve. Le public est jeune, la musique est forte, et l''ambiance est celle d''un spring break urbain chic.');
