bnA-HNvdBG6tiztCaOnE7y2YPib20ub3qEjQyzX-78Wm4t3rMm_LJgrMiCAeynpjOrPnidwB-C3fqWl6awB8LhDUVGKvZWSBkiQiSg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"• La formule Ardoise à 31€ est l''une des meilleures affaires du quartier Alésia.\n• La salle pouvant être animée le soir, la terrasse en angle est très prisée aux beaux jours (non réservable).\n• L''établissement possède une excellente sélection de blancs de Loire hors-carte pour accompagner le poisson.\n• Ne passez pas à côté du Cheesecake Pistache, plébiscité par les habitués.","specials":{"cuisine":["Bistronomie","Viandes Françaises","Fait Maison"],"drinks":["Vins de Producteurs","Blancs de Loire","Softs Artisanaux"],"must_eat":"Le Confit de Canard fondant & le Cheesecake Pistache.","expert_catchline":"Bistronomie franche, sourcing pointu et générosité au cœur du 14e."}}', 'Niché rue Alphonse Daudet, Chez Alphonse est l''archétype du néo-bistrot de quartier réussi. Le lieu marie avec élégance des cloisons modernes, de confortables banquettes et de grandes tablées boisées sous une belle hauteur de plafond. Ici, la cuisine française traditionnelle est exécutée avec la précision d''un restaurant gastronomique mais servie avec la générosité d''une brasserie. Le sourcing est au cœur de l''assiette, privilégiant les circuits courts et les produits d''artisans. C''est une valeur sûre, aussi bien pour un déjeuner rapide que pour un dîner épicurien, portée par une équipe d''une efficacité redoutable.', '• La formule Ardoise à 31€ est l''une des meilleures affaires du quartier Alésia.
INSERT INTO places_fts VALUES ('poi-chez-alphonse-75014', 'Chez Alphonse', 'restaurant', 'bistro traditionnel terrasse fait-maison ardoise convivial', '16 Rue Alphonse Daudet', '', 'Niché rue Alphonse Daudet, Chez Alphonse est l''archétype du néo-bistrot de quartier réussi. Le lieu marie avec élégance des cloisons modernes, de confortables banquettes et de grandes tablées boisées sous une belle hauteur de plafond. Ici, la cuisine française traditionnelle est exécutée avec la précision d''un restaurant gastronomique mais servie avec la générosité d''une brasserie. Le sourcing est au cœur de l''assiette, privilégiant les circuits courts et les produits d''artisans. C''est une valeur sûre, aussi bien pour un déjeuner rapide que pour un dîner épicurien, portée par une équipe d''une efficacité redoutable.');
INSERT INTO places VALUES ('poi-160', 'La Closerie des Lilas', 'closerie-des-lilas', 'restaurant', 'brasserie-litteraire', 'chill', 48.840144, 2.336043, 14, '171 Bd du Montparnasse', '#8ccaf7', 'pin', 1, 4.4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0uN0cwiLl4ZYuZH7hDPmn3S_LiX1mUnBJdk795WPDckVh9CB7059C-1k4WeE2NOn-EXjhfWyzTlVWa6VWZLbo5iLqblCaiMDulWxBCToI_uVWbfKT_HRE7Q9sk_2c0GipJsWVDUpmNuooPLc4XPwia30LBR1Ip3pGv3AQfALFXvKMukyz8D9MyTypfFohZKP874emr2e7AKEKL4zapXhvwYbsG-MjI91x-y5V1FFGxTwahxcXGu6cg4WzdiQO_qDY70fD7HRbTgcZOzqOKh8rpyDSd3HG7MDvMPNJdT_pPXw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 35, 0, '€', NULL, NULL, NULL, 0, 35, 50, '{"chill":21,"festif":4,"culturel":5}', '{}', '["restaurant","brasserie-litteraire"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":35,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":35,"budget_avg":35,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":35,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0uN0cwiLl4ZYuZH7hDPmn3S_LiX1mUnBJdk795WPDckVh9CB7059C-1k4WeE2NOn-EXjhfWyzTlVWa6VWZLbo5iLqblCaiMDulWxBCToI_uVWbfKT_HRE7Q9sk_2c0GipJsWVDUpmNuooPLc4XPwia30LBR1Ip3pGv3AQfALFXvKMukyz8D9MyTypfFohZKP874emr2e7AKEKL4zapXhvwYbsG-MjI91x-y5V1FFGxTwahxcXGu6cg4WzdiQO_qDY70fD7HRbTgcZOzqOKh8rpyDSd3HG7MDvMPNJdT_pPXw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'La Closerie des Lilas est l''un des sanctuaires de la vie bohème et littéraire du Paris de la Belle Époque. On y vient pour son bar mythique au décor de bois sombre, où Hemingway avait ses quartiers, ou pour sa brasserie élégante. Entre piano-bar et parfum de lilas, le lieu dégage une poésie folle que les années n''ont pas entamée. C''est le rendez-vous des amoureux des lettres et de l''art de vivre à la française, chic sans être arrogant.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-160', 'La Closerie des Lilas', 'restaurant', 'brasserie-litteraire', '171 Bd du Montparnasse', '', 'La Closerie des Lilas est l''un des sanctuaires de la vie bohème et littéraire du Paris de la Belle Époque. On y vient pour son bar mythique au décor de bois sombre, où Hemingway avait ses quartiers, ou pour sa brasserie élégante. Entre piano-bar et parfum de lilas, le lieu dégage une poésie folle que les années n''ont pas entamée. C''est le rendez-vous des amoureux des lettres et de l''art de vivre à la française, chic sans être arrogant.');
INSERT INTO places VALUES ('poi-162', 'Crêperie Josselin', 'creperie-josselin', 'restaurant', 'creperie', 'chill', 48.841867, 2.325564, 14, '59 Rue du Montparnasse', '#8ccaf7', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN30z0ZyxDGc90qxGLXHNb3KK2BWyDBsQJlipiReKHCnxq4bhByG28BhsYc4zKOMWCzdBgXOpO6TNFiUhk5Nx_lAlg6PDLpUIpf87fQ5YI179DIT7PHVNdLDH-317U48LMT2eDGD93fPF6q0nw64pnc9uAYLJDrZ2hUSSpiyerdkzPGP-sDWL4JaWHibuor27qDTX9Byrkn_U7pueku_kCJBvsuJSeYRSgzTXNpiQ2nKLBvSE0Mas3ZFWgw-6alIXHvjsO8aMEFdKGSof7XocBelVe7SqYGZ1jWJxd-EMnWmgn4WLLGWkurP7dHU3_8M2rXoPS9nJFRbWLFA_lXcE10U0HartD8v8fwlr352ui2Bsqd4Vv8CiyW-wW9JL_6Uj8uCRNX-3gxBzAuvuBLhlXrSgG2f9WnwFZfXDxDDvVjEDTi6&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 12, 0, '€', NULL, NULL, NULL, 4, 12, 50, '{"chill":21,"festif":4,"culturel":5}', '{}', '["restaurant","creperie"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":4,"dish_price":12,"budget_avg":12,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":12,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN30z0ZyxDGc90qxGLXHNb3KK2BWyDBsQJlipiReKHCnxq4bhByG28BhsYc4zKOMWCzdBgXOpO6TNFiUhk5Nx_lAlg6PDLpUIpf87fQ5YI179DIT7PHVNdLDH-317U48LMT2eDGD93fPF6q0nw64pnc9uAYLJDrZ2hUSSpiyerdkzPGP-sDWL4JaWHibuor27qDTX9Byrkn_U7pueku_kCJBvsuJSeYRSgzTXNpiQ2nKLBvSE0Mas3ZFWgw-6alIXHvjsO8aMEFdKGSof7XocBelVe7SqYGZ1jWJxd-EMnWmgn4WLLGWkurP7dHU3_8M2rXoPS9nJFRbWLFA_lXcE10U0HartD8v8fwlr352ui2Bsqd4Vv8CiyW-wW9JL_6Uj8uCRNX-3gxBzAuvuBLhlXrSgG2f9WnwFZfXDxDDvVjEDTi6&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'La Crêperie Josselin est sans doute la plus célèbre de tout le quartier de Montparnasse. Dans un décor rustique de vieille auberge bretonne, on y sert des galettes de sarrasin au beurre (salé!) d une finesse et d une régularité absolues. Le cidre y coule à flot et l ambiance est joyeuse, rythmée par le ballet incessant des serveurs. C''est le rendez-vous obligé des familles et des amoureux de la tradition bretonne, pour une expérience authentique et généreuse qui ne déçoit jamais.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-162', 'Crêperie Josselin', 'restaurant', 'creperie', '59 Rue du Montparnasse', '', 'La Crêperie Josselin est sans doute la plus célèbre de tout le quartier de Montparnasse. Dans un décor rustique de vieille auberge bretonne, on y sert des galettes de sarrasin au beurre (salé!) d une finesse et d une régularité absolues. Le cidre y coule à flot et l ambiance est joyeuse, rythmée par le ballet incessant des serveurs. C''est le rendez-vous obligé des familles et des amoureux de la tradition bretonne, pour une expérience authentique et généreuse qui ne déçoit jamais.');
INSERT INTO places VALUES ('poi-165', 'La Coupole', 'la-coupole', 'restaurant', 'brasserie-art-deco', 'chill', 48.842255, 2.327951, 14, '102 Bd du Montparnasse', '#8ccaf7', 'pin', 1, 4.4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3xEmd6D-wp9EPkCobOCPWm9opvwkm7fyR37dJMO2uQWTKAd0WkrvKogNJhDe4IaA0WQk5rg59la5CUg7JStJXhhlqr8tdUwx6xsXN6V7GnBgILVwWUeJ25nEfCVdABrFm-fcWPiXyWXvhAsiCPwQyrZ8g_ImpJtE3fNNfmCxJiwvIBJEeBcnC1wJx6lD66vr2QCklTXz0ljGjsQNVOnT-8dFoPpDlSUhbC-46J72dBlPkZ6Tjkd8YsEwUy3IVc166lbSq3h7AePecro-UpZme2cL-5NBajg2H0uNuOzwcxwg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 24, 0, '€', NULL, NULL, NULL, 0, 24, 50, '{"chill":21,"festif":4,"culturel":5}', '{}', '["restaurant","brasserie-art-deco"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":24,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":24,"budget_avg":24,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":24,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3xEmd6D-wp9EPkCobOCPWm9opvwkm7fyR37dJMO2uQWTKAd0WkrvKogNJhDe4IaA0WQk5rg59la5CUg7JStJXhhlqr8tdUwx6xsXN6V7GnBgILVwWUeJ25nEfCVdABrFm-fcWPiXyWXvhAsiCPwQyrZ8g_ImpJtE3fNNfmCxJiwvIBJEeBcnC1wJx6lD66vr2QCklTXz0ljGjsQNVOnT-8dFoPpDlSUhbC-46J72dBlPkZ6Tjkd8YsEwUy3IVc166lbSq3h7AePecro-UpZme2cL-5NBajg2H0uNuOzwcxwg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Inaugurée en 1927, La Coupole est une cathédrale de l’Art Déco. Ses 33 piliers peints par les artistes de la bohème de Montparnasse surveillent toujours la salle immense et vibrante. C’est le lieu de tous les brassages : on y croise aussi bien des touristes émerveillés que le Tout-Paris de la culture. Entre curry d agneau légendaire découpé au guéridon et plateaux de fruits de mer monumentaux, La Coupole reste le témoin flamboyant d''un Paris qui n''a jamais cessé de fêter la vie.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-165', 'La Coupole', 'restaurant', 'brasserie-art-deco', '102 Bd du Montparnasse', '', 'Inaugurée en 1927, La Coupole est une cathédrale de l’Art Déco. Ses 33 piliers peints par les artistes de la bohème de Montparnasse surveillent toujours la salle immense et vibrante. C’est le lieu de tous les brassages : on y croise aussi bien des touristes émerveillés que le Tout-Paris de la culture. Entre curry d agneau légendaire découpé au guéridon et plateaux de fruits de mer monumentaux, La Coupole reste le témoin flamboyant d''un Paris qui n''a jamais cessé de fêter la vie.');
