RqfPR9D4MY-npBEZSy2bU49wKZHJM3XSNX3tajtiRK-nbv8cyvg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfW1uVPhqZ_S_6cSwakKgz2-9hC5f09VY92SlXEwdVjK8wDbToNggd2KGZ9JXEVolfqPnqhxfVGZuxgTdX2AL_IDwnMuAFI-mgFMlN-32nC5t36pPam_O95e9Qu9vtii03KZb_Hfxi6_Pe9UB6HyuWZ4u3mTCKXv28VnWlPPB8AdO4qoUIRLMjdaN0S3dGt---IqSe7gRD6BKKqb94og-ckdjo_b2Zv6WK-Z1zAoMvJV1-gITRZ2-ce4RE6qt7I8Ncv9Hy0NlFzVA7Ke3E-9N6a9invYJ1MB3HO2cNol4D5Jnbw9kcwsXsC3e-0TfJOkcS_E5nJQJEGMTymSVOybn5z8MgR41GxFNXAeu5G7lvQ90op_NObSKuJngq-owzUNgiUcPdbncOey8I3JBcbnPUDliT6KE6Xo65TwDhAiilKTXXaDdLS9mBzmTlK7rgBE&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]}', '["https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfU734ljv6OLyxh7x3hxzOWEjJJfNW4Jnf1-srXkstl5EwkiAS0ar4kOpPJForqmJtxsMoqSPb9gyPGfVbZgbK7wyvrPE4boJOzk2sjvHeIIxYSF8h1uhXBgVSWkKhGIrl2BibsO-o7B9-8D2rNlue4JXLAkouD5JV0hUjdFKU39GumzBawDr0tBkKpUtQd2tJyD_3TU15Skf04scswE6DoflwtUopzi3v3S4hiuBuqcuVboizm7UPj-qVbRqfPR9D4MY-npBEZSy2bU49wKZHJM3XSNX3tajtiRK-nbv8cyvg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfW1uVPhqZ_S_6cSwakKgz2-9hC5f09VY92SlXEwdVjK8wDbToNggd2KGZ9JXEVolfqPnqhxfVGZuxgTdX2AL_IDwnMuAFI-mgFMlN-32nC5t36pPam_O95e9Qu9vtii03KZb_Hfxi6_Pe9UB6HyuWZ4u3mTCKXv28VnWlPPB8AdO4qoUIRLMjdaN0S3dGt---IqSe7gRD6BKKqb94og-ckdjo_b2Zv6WK-Z1zAoMvJV1-gITRZ2-ce4RE6qt7I8Ncv9Hy0NlFzVA7Ke3E-9N6a9invYJ1MB3HO2cNol4D5Jnbw9kcwsXsC3e-0TfJOkcS_E5nJQJEGMTymSVOybn5z8MgR41GxFNXAeu5G7lvQ90op_NObSKuJngq-owzUNgiUcPdbncOey8I3JBcbnPUDliT6KE6Xo65TwDhAiilKTXXaDdLS9mBzmTlK7rgBE&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"• Ne sous-estimez JAMAIS la taille de la Salade Boyarde, elle suffit à caler deux petits appétits.\n• La terrasse de 30 places est très prisée aux beaux jours, mais l''intérieur avec sa mezzanine est super cosy en hiver.\n• Pour les amateurs de vin, le pichet de ''Cuvée Papa'' est d''un rapport qualité-prix imbattable pour le quartier.\n• C''est le refuge parfait si vous ratez votre train à Montparnasse : service continu et ambiance qui réchauffe le cœur.","specials":{"cuisine":["Sud-Ouest","Confit","Cassoulet"],"drinks":["Cuvée Papa","Buzet","Pinte 50cl HH"],"must_eat":"Le Cassoulet Spécial Papa ou l''Escalope Montagnarde pour les plus courageux.","expert_catchline":"L''ambiance des Landes et des assiettes qui n''en finissent plus."}}', 'Véritable enclave du Sud-Ouest sur le Boulevard du Montparnasse. Chez Papa (Vavin) est célèbre pour ses portions démentielles et son atmosphère de fête villageoise. Ici, on ne plaisante pas avec la faim : les salades sont servies dans des saladiers et le cassoulet arrive fumant dans sa cassole. La déco rustique, les nappes à carreaux et le service dynamique vous transportent directement dans les Landes sans quitter le 14ème.', '• Ne sous-estimez JAMAIS la taille de la Salade Boyarde, elle suffit à caler deux petits appétits.
INSERT INTO places_fts VALUES ('poi-chez-papa-montparnasse', 'Chez Papa Montparnasse', 'restaurant', 'bar brasserie sud-ouest terrasse traditionnel', '138 Boulevard du Montparnasse', '', 'Véritable enclave du Sud-Ouest sur le Boulevard du Montparnasse. Chez Papa (Vavin) est célèbre pour ses portions démentielles et son atmosphère de fête villageoise. Ici, on ne plaisante pas avec la faim : les salades sont servies dans des saladiers et le cassoulet arrive fumant dans sa cassole. La déco rustique, les nappes à carreaux et le service dynamique vous transportent directement dans les Landes sans quitter le 14ème.');
INSERT INTO places VALUES ('poi-164', 'Le Rosebud', 'le-rosebud', 'bar', 'bar-cocktail, bar-litteraire, speakeasy', 'chill', 48.841661, 2.328279, 14, '11 bis Rue Delambre', '#8ccaf7', 'pin', 1, 4.2, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2LOXxi641Y7huQi-S89QA2HSm2nHBGisaaf-Wo4XY2uAIs1LEc3pCO9wZMSCX9fRCYYIBt9opQdGy4bGxIq8Uqtjpb0Bk0eWZem-rIKqR-ZNgsLXqt1bayMJRn4vmb88DOIcNNxq3g3RXKd65Ar_C7YKBEhd0htgVTOqPsQRc2hHVOi22dSyFmJf5AhqujRBAuLvoK4HIUMO3QYC8LAisgpv2DasBr3BxBp8NzVlUWXOGbq5C4mXVnoMa01gBOMUF5xQ6uXF2tTnAM3xKfnS27FswevN0C3zyDVMOcl1tRKw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 8, 0, '€', 8, 17, NULL, 3.5, 16, 50, '{"chill":30,"festif":15,"culturel":15}', '{}', '["bar","bar-cocktail","bar-litteraire","speakeasy"]', '{"standard":"mardi: 18:30-02:00\nmercredi: 18:30-02:00\njeudi: 18:30-02:00\nvendredi: 18:30-02:00\nsamedi: 18:30-02:00\ndimanche: Fermé\nlundi: Fermé","display":"mardi: 18:30-02:00","detailed":"mardi: 18:30-02:00\nmercredi: 18:30-02:00\njeudi: 18:30-02:00\nvendredi: 18:30-02:00\nsamedi: 18:30-02:00\ndimanche: Fermé\nlundi: Fermé","is_open_now":false}', '{"reservation_policy":"sans_resa","accessibility":false,"wifi":false,"terrace":true,"opening_hours_raw":"mardi: 18:30-02:00\nmercredi: 18:30-02:00\njeudi: 18:30-02:00\nvendredi: 18:30-02:00\nsamedi: 18:30-02:00\ndimanche: Fermé\nlundi: Fermé","action_type":"site","action_url":"","cuisine_type":"Bar à cocktails","price_info":{"smart_tip":"Les cocktails sont généreusement dosés, un seul suffit souvent. Service à l''ancienne avec serveurs en chemise blanche.","items":[{"category":"COCKTAILS SIGNATURES","items":[{"name":"Rosebud (gin, crème de rose, cerise, citron, champagne)","price":"18€"},{"name":"Citizen Kane (champagne, gin, crème de rose, citron)","price":"17€"},{"name":"Blue Velvet (gin, Noilly Prat, surapawa, violette, gingembre)","price":"17€"}]},{"category":"COCKTAILS CLASSIQUES","items":[{"name":"Dry Martini (twist ou olive)","price":"17€"},{"name":"Old Fashioned (Maker''s Mark, rapadura, cerise marasquin)","price":"18€"},{"name":"Negroni","price":"16€"},{"name":"Manhattan","price":"17€"},{"name":"Moscow Mule","price":"15€"},{"name":"Singapore Sling","price":"17€"},{"name":"Bloody Mary (anthologie)","price":"16€"},{"name":"Pick Me Up","price":"16€"},{"name":"Paris 75","price":"17€"}]},{"category":"ASSIETTES (8€ - 24€)","items":[{"name":"Œufs mayonnaise","price":"8€"},{"name":"Tarama nature","price":"10€"},{"name":"Jambon Bellota","price":"16€"},{"name":"Tempura de légumes","price":"12€"},{"name":"Croque-monsieur","price":"12€"},{"name":"Chili con carne R62","price":"16€"},{"name":"Tartare de bœuf","price":"18€"},{"name":"Burger","price":"18€"},{"name":"Jambon, œufs et frites","price":"16€"},{"name":"Pâtes Alfredo","price":"14€"},{"name":"Assiette de fromages","price":"14€"}]},{"category":"VINS","items":[{"name":"Vins nature (sélection)","price":"8€-12€"}]}]},"happy_hour":null}', '{"avg_budget":18,"is_free":false,"pint_price":8,"cocktail_price":17,"coffee_price":3.5,"dish_price":16,"last_updated":"2026-02-06","budget_avg":8,"type":"bar","menu_items":[],"_debug_manual_dish_price":16,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2LOXxi641Y7huQi-S89QA2HSm2nHBGisaaf-Wo4XY2uAIs1LEc3pCO9wZMSCX9fRCYYIBt9opQdGy4bGxIq8Uqtjpb0Bk0eWZem-rIKqR-ZNgsLXqt1bayMJRn4vmb88DOIcNNxq3g3RXKd65Ar_C7YKBEhd0htgVTOqPsQRc2hHVOi22dSyFmJf5AhqujRBAuLvoK4HIUMO3QYC8LAisgpv2DasBr3BxBp8NzVlUWXOGbq5C4mXVnoMa01gBOMUF5xQ6uXF2tTnAM3xKfnS27FswevN0C3zyDVMOcl1tRKw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez avant 22h pour avoir une banquette. Goûtez le Chili con carne, la recette historique de la maison qui n''a jamais changé.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Une véritable institution de Montparnasse qui a vu défiler le tout-Paris intellectuel, de Sartre à Marguerite Duras. Le Rosebud n''essaie pas d''être à la mode, il est le style. Avec ses banquettes en velours, sa moquette feutrée et ses serveurs en veste blanche, l''ambiance est celle d''un confort intemporel, propice aux confidences. La carte est une bible du cocktail classique, exécuté avec une précision chirurgicale et des doses généreuses. C''est le refuge idéal pour ceux qui cherchent une élégance discrète et une atmosphère jazz, loin de l''agitation m''as-tu-vu.', 'Arrivez avant 22h pour avoir une banquette. Goûtez le Chili con carne, la recette historique de la maison qui n''a jamais changé.', 'Vavin', '[4]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-164', 'Le Rosebud', 'bar', 'bar-cocktail bar-litteraire speakeasy', '11 bis Rue Delambre', '', 'Une véritable institution de Montparnasse qui a vu défiler le tout-Paris intellectuel, de Sartre à Marguerite Duras. Le Rosebud n''essaie pas d''être à la mode, il est le style. Avec ses banquettes en velours, sa moquette feutrée et ses serveurs en veste blanche, l''ambiance est celle d''un confort intemporel, propice aux confidences. La carte est une bible du cocktail classique, exécuté avec une précision chirurgicale et des doses généreuses. C''est le refuge idéal pour ceux qui cherchent une élégance discrète et une atmosphère jazz, loin de l''agitation m''as-tu-vu.');
INSERT INTO places VALUES ('poi-159', 'Le Select', 'le-select', 'café', 'cafe-historique', 'chill', 48.842612, 2.328407, 14, '99 Bd du Montparnasse', '#8ccaf7', 'pin', 1, 4.2, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1kkrVyD3C8e3d4zkJtoTq5D5UOt50Ty5gSRB54-_yzQm-k3uWDUBjnf6d23aWUL2WORkhbXRo80tva14n8fWHj3V3_7OjTYa3nZqRrB-wgMtleDw4wKw7xxyuqSLsroZkxuHKJQA4Lm6OBwLe_UQQXBLedReSegwE0un3yT6OCJa6LRhuXkPR40qE8-F4B0gM7gb1eYcs2yO_1ZgPHo4tXn3qGvsBDHLnWlnn64RhapG66j6Sv8dRla_0U29zCtP6ZT5EygqPiZgkGSztmRZkaFbhd4xfcu-cnPmzMP1D9zA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 3.5, 0, '€', NULL, NULL, NULL, 3.5, 0, 50, '{"chill":23,"festif":4,"culturel":5}', '{}', '["café","cafe-historique"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":3.5,"dish_price":0,"budget_avg":3.5,"type":"cafe","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1kkrVyD3C8e3d4zkJtoTq5D5UOt50Ty5gSRB54-_yzQm-k3uWDUBjnf6d23aWUL2WORkhbXRo80tva14n8fWHj3V3_7OjTYa3nZqRrB-wgMtleDw4wKw7xxyuqSLsroZkxuHKJQA4Lm6OBwLe_UQQXBLedReSegwE0un3yT6OCJa6LRhuXkPR40qE8-F4B0gM7gb1eYcs2yO_1ZgPHo4tXn3qGvsBDHLnWlnn64RhapG66j6Sv8dRla_0U29zCtP6ZT5EygqPiZgkGSztmRZkaFbhd4xfcu-cnPmzMP1D9zA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''adresse préférée des locaux, loin des foules habituelles.","specials":{"cuisine":[],"drinks":[]}}', 'Le Select est une machine à remonter le temps. Entrer dans ce café mythique de Montparnasse, c''est s''asseoir là où Picasso, Hemingway ou Fitzgerald ont refait le monde. Le décor Art Déco est resté intact, feutré par les années d''histoire littéraire et artistique. C''est l''un des rares cafés parisiens qui conserve son âme noctambule et sa dignité de grand classique, offrant un service impeccable et une terrasse légendaire sur le boulevard.', 'L''adresse préférée des locaux, loin des foules habituelles.', 'Vavin', '[4]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-159', 'Le Select', 'café', 'cafe-historique', '99 Bd du Montparnasse', '', 'Le Select est une machine à remonter le temps. Entrer dans ce café mythique de Montparnasse, c''est s''asseoir là où Picasso, Hemingway ou Fitzgerald ont refait le monde. Le décor Art Déco est resté intact, feutré par les années d''histoire littéraire et artistique. C''est l''un des rares cafés parisiens qui conserve son âme noctambule et sa dignité de grand classique, offrant un service impeccable et une terrasse légendaire sur le boulevard.');
INSERT INTO places VALUES ('poi-075', 'L''Abreuvoir', 'abreuvoir', 'bar', 'terrasse', 'festif', 48.851938, 2.288929, 15, '24 Rue du Dr Finlay', '#ffab60', 'pin', 1, 4.6, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3PfLb6neJNI8upIOZfW7CJJqFlJC2cPWycXI8YwDar7hzYV6JimumXQ91JsRBJ00sGVG5x5X7z1p0ebaftbLjcdOjI6dYakTEGU-dsSHgNxkqaGk-oAu7LhxoE6rsM4E30Eiw_cU5DNHoU8BU9DhcNh5DvS7yO6baS3vdFGHvx0GjzjXvIqBtbUh7-RMmdDlLk2DtJjm6Db0btyRSsYgKsGZTIbFaVwMwago6TyEsjeu-SGNfGD1-jYbkNjkQPEnrV7bQW7QD_41k5FifQevDHMmVez0-s282Ey1TxZ7gHZg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 5, 0, '€', 5, NULL, NULL, 0, 15, 50, '{"chill":5.8,"festif":23,"culturel":6}', '{}', '["bar","terrasse"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":5,"cocktail_price":0,"coffee_price":0,"dish_price":15,"budget_avg":5,"type":"bar","menu_items":[],"_debug_manual_dish_price":15,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3PfLb6neJNI8upIOZfW7CJJqFlJC2cPWycXI8YwDar7hzYV6JimumXQ91JsRBJ00sGVG5x5X7z1p0ebaftbLjcdOjI6dYakTEGU-dsSHgNxkqaGk-oAu7LhxoE6rsM4E30Eiw_cU5DNHoU8BU9DhcNh5DvS7yO6baS3vdFGHvx0GjzjXvIqBtbUh7-RMmdDlLk2DtJjm6Db0btyRSsYgKsGZTIbFaVwMwago6TyEsjeu-SGNfGD1-jYbkNjkQPEnrV7bQW7QD_41k5FifQevDHMmVez0-s282Ey1TxZ7gHZg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Situé à deux pas du quartier Beaugrenelle, L''Abreuvoir est l''un de ces ports d''attache indispensables du 15ème arrondissement. Sa grande terrasse plein soleil est le point de ralliement des after-works et des soirées entre amis qui s''éternisent. L''accueil y est chaleureux et la carte simple mais efficace : des planches généreuses et des bières fraîches. C''est un lieu sans prétention, vivant et convivial, qui apporte une touche de légèreté et de fête dans un quartier parfois trop calme.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-075', 'L''Abreuvoir', 'bar', 'terrasse', '24 Rue du Dr Finlay', '', 'Situé à deux pas du quartier Beaugrenelle, L''Abreuvoir est l''un de ces ports d''attache indispensables du 15ème arrondissement. Sa grande terrasse plein soleil est le point de ralliement des after-works et des soirées entre amis qui s''éternisent. L''accueil y est chaleureux et la carte simple mais efficace : des planches généreuses et des bières fraîches. C''est un lieu sans prétention, vivant et convivial, qui apporte une touche de légèreté et de fête dans un quartier parfois trop calme.');
