INSERT INTO places VALUES ('poi-118', 'Monsieur Bleu', 'monsieur-bleu', 'restaurant', 'chic / terrasse', 'culturel', 48.864587, 2.296675, 16, 'Palais De Tokyo', '#c499ff', 'pin', 1, 4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0s4ot7cJKOHB8Qqx9HPP1z38REmo84siaTecJtM5ejQXdZxtxCBB77_FZqgcI4Xxl_hx1--rUBKgKjLzPczFyzPoLxn4BPjPuqNtzYBoKNIjhsI3LCv5SnWRFGkAs-Mk0q-hOAAwBnVSRus195cXGCcAPap07M7buxnm1QfnWI3qcXtc1kyOXPWUurEjlbOk3brhcCdgPpW-gPJNz_ffleDeiLppWzzgf-hyYsxuPIy2Y7eHOwViYfJ3Gn5QVN45Qmokpz9b3ul5DGrhlgWfIjzprRwh6Ix3y10RyEQdrOtg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 28, 0, '€', NULL, NULL, NULL, 0, 28, 50, '{"chill":8,"festif":7,"culturel":25}', '{}', '["restaurant","chic / terrasse"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":30.5,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":28,"budget_avg":28,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":28,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0s4ot7cJKOHB8Qqx9HPP1z38REmo84siaTecJtM5ejQXdZxtxCBB77_FZqgcI4Xxl_hx1--rUBKgKjLzPczFyzPoLxn4BPjPuqNtzYBoKNIjhsI3LCv5SnWRFGkAs-Mk0q-hOAAwBnVSRus195cXGCcAPap07M7buxnm1QfnWI3qcXtc1kyOXPWUurEjlbOk3brhcCdgPpW-gPJNz_ffleDeiLppWzzgf-hyYsxuPIy2Y7eHOwViYfJ3Gn5QVN45Qmokpz9b3ul5DGrhlgWfIjzprRwh6Ix3y10RyEQdrOtg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Installé dans l''aile ouest du Palais de Tokyo, Monsieur Bleu est une brasserie cosmopolite au design impeccable signé Joseph Dirand. Avec ses volumes impressionnants, son marbre noir et ses touches de vert, le lieu dégage une élégance folle. Sa terrasse immense, probablement l''une des plus belles de Paris, offre un face-à-face spectaculaire avec la Tour Eiffel, idéal pour un déjeuner chic ou un cocktail au crépuscule.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
