INSERT INTO places VALUES ('poi-195', 'Musée de l''Homme', 'musee-de-lhomme', 'museum', 'anthropologie', 'culturel', 48.861166, 2.286826, 16, '17 Pl. du Trocadéro et du 11 Novembre, 75116 Paris, France', '#c499ff', 'pin', 1, 4.4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0ZstW0I_-67W6VW-AL0SVe8pWDMWmNzq35j7LIqB7yigm5OOvuGao2970dnXZZRlf__vGwaU5CiVg250_YWKQCRe5NS2bxoyzvKFxlrNo0wrV_V32BtQUG6kYxJdTl4OK7LAt5yWhVL4ls-72n3YkQtoqWzXZABD4qOBVwB43KvAMjAyfLY9TOy1H-FytE0DZx1gvjK4DLg06G-ruWjpt8x8IkSaMNuzSVWcSx5sga3ZODQAZ395ldHEODDIqZMWacdgRZ2don2HfnRjJ6kSE5PJSUBbFDi5DTE9X25VBbHQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":6,"festif":4,"culturel":24}', '{}', '["museum","anthropologie"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":14,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":15,"type":"museum","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0ZstW0I_-67W6VW-AL0SVe8pWDMWmNzq35j7LIqB7yigm5OOvuGao2970dnXZZRlf__vGwaU5CiVg250_YWKQCRe5NS2bxoyzvKFxlrNo0wrV_V32BtQUG6kYxJdTl4OK7LAt5yWhVL4ls-72n3YkQtoqWzXZABD4qOBVwB43KvAMjAyfLY9TOy1H-FytE0DZx1gvjK4DLg06G-ruWjpt8x8IkSaMNuzSVWcSx5sga3ZODQAZ395ldHEODDIqZMWacdgRZ2don2HfnRjJ6kSE5PJSUBbFDi5DTE9X25VBbHQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'Le Musée de l''Homme répond avec modernité aux questions fondamentales de notre existence : qui sommes-nous, d''où venons-nous et où allons-nous ? Dans un espace totalement repensé et interactif, on suit l''aventure humaine de la préhistoire aux enjeux technologiques de demain. Installé place du Trocadéro, il offre une vue plongeante sur la Dame de Fer tout en nous rappelant notre fragilité et notre grandeur à travers l''Histoire de l''Espèce.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL);
