INSERT INTO places VALUES ('poi-210', 'Breizh Café Batignolles', 'breizh-cafe-batignolles', 'restaurant', 'creperie', 'chill', 48.884915, 2.320718, 17, '31 Rue des Batignolles', '#8ccaf7', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0EEPPOP2_mpWmM22xp-HLnBIpJyhGJyNuFNX7RwBoiw5dS30or6SWhAtWoCZ5dTXucQz8n8wf4KIjMgGMwezWz5n6SGq--EPSrRam1ajfw-RFtBl_XfIm_rjmy5S_DqdFsVKg-ThJv48aaTp5JOH1gHnKdKgeaFJnl81dGae31Doo2WPRA0rR7uQFdcijn6KmSehbvLGXlUChCbFomET7x-8zcueACNG82NJTo7qTTp70EhOIuGG0JQ_9MprFJGRxcyNHqN2IHgDLwK0Hqb5mpE-6lbOKXrdlOiXNgkkOSNQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 25, 0, '€', NULL, NULL, NULL, 0, 25, 50, '{"chill":21,"festif":4,"culturel":5}', '{}', '["restaurant","creperie"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":25,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":25,"budget_avg":25,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":25,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0EEPPOP2_mpWmM22xp-HLnBIpJyhGJyNuFNX7RwBoiw5dS30or6SWhAtWoCZ5dTXucQz8n8wf4KIjMgGMwezWz5n6SGq--EPSrRam1ajfw-RFtBl_XfIm_rjmy5S_DqdFsVKg-ThJv48aaTp5JOH1gHnKdKgeaFJnl81dGae31Doo2WPRA0rR7uQFdcijn6KmSehbvLGXlUChCbFomET7x-8zcueACNG82NJTo7qTTp70EhOIuGG0JQ_9MprFJGRxcyNHqN2IHgDLwK0Hqb5mpE-6lbOKXrdlOiXNgkkOSNQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Breizh Café aux Batignolles, c''est l''excellence de la galette bretonne avec une touche de raffinement japonais. Les galettes de sarrasin sont craquantes à souhait, beurrées au beurre Bordier et garnies de produits d''exception. Le décor est boisé, sobre et élégant, tranchant avec les crêperies traditionnelles. Une carte de cidres exceptionnelle (plus de 60 références!) complète l''expérience, faisant de ce lieu le rendez-vous chic et authentique des amoureux de l''Armorique dans le 17ème.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
