INSERT INTO places VALUES ('poi-215', 'Les Caves de Courcelles', 'caves-courcelles', 'bar', 'bar-a-vin', 'festif', 48.886826, 2.29577, 17, '206 Bis Rue de Courcelles', '#ffab60', 'pin', 1, 4.9, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2qJ_XNza1caC3ZRJnQzM4dFU0QG1lfHFMfkyEfpS9AauMRmNyhWeycQjyNEKlPgRfYT_-MSTfFaNT9-DeOZEKRaaIcwhT0k1frDGOljJvCAZfDiWzkecJL_DOd_BclByVriMUcZcrnxv0whxNWw1bK9MQpBwZ5sIhGtsGXqiTyfNM6E4Jq19u46_fxHvy5CxVjWlS1lgZpD63MSq9Zvq8oVl8z0a5gTxX9MEBfTN4G4Xybr1zmzz83eADYUD6VSQMROnxyMbchwmJm_vXqk4sLA2gjM-VS-iUBUfVLy9TpJw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 7.5, 0, '€', 7.5, NULL, NULL, 0, 0, 50, '{"chill":6,"festif":23,"culturel":5}', '{}', '["bar","bar-a-vin"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":16,"is_free":false,"pint_price":7.5,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":7.5,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2qJ_XNza1caC3ZRJnQzM4dFU0QG1lfHFMfkyEfpS9AauMRmNyhWeycQjyNEKlPgRfYT_-MSTfFaNT9-DeOZEKRaaIcwhT0k1frDGOljJvCAZfDiWzkecJL_DOd_BclByVriMUcZcrnxv0whxNWw1bK9MQpBwZ5sIhGtsGXqiTyfNM6E4Jq19u46_fxHvy5CxVjWlS1lgZpD63MSq9Zvq8oVl8z0a5gTxX9MEBfTN4G4Xybr1zmzz83eADYUD6VSQMROnxyMbchwmJm_vXqk4sLA2gjM-VS-iUBUfVLy9TpJw&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.","specials":{"cuisine":[],"drinks":["Vin"]}}', 'Les Caves de Courcelles, c''est le bar à vin de quartier dont on ne se lasse jamais. Ici, pas de snobisme, seulement de l amour pour le vin et la convivialité. Les murs couverts de bouteilles annoncent la couleur : la sélection est vaste, pointue et souvent axée sur des petits producteurs méconnus. On s installe sur le zinc ou autour d un fût pour partager des planches de charcuteries artisanales généreuses dans une ambiance de village qui fait chaud au cœur, en plein cœur du 17ème arrondissement.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-215', 'Les Caves de Courcelles', 'bar', 'bar-a-vin', '206 Bis Rue de Courcelles', '', 'Les Caves de Courcelles, c''est le bar à vin de quartier dont on ne se lasse jamais. Ici, pas de snobisme, seulement de l amour pour le vin et la convivialité. Les murs couverts de bouteilles annoncent la couleur : la sélection est vaste, pointue et souvent axée sur des petits producteurs méconnus. On s installe sur le zinc ou autour d un fût pour partager des planches de charcuteries artisanales généreuses dans une ambiance de village qui fait chaud au cœur, en plein cœur du 17ème arrondissement.');
INSERT INTO places VALUES ('poi-202', 'Coretta', 'coretta-paris', 'restaurant', 'bistronomie', 'chill', 48.89058, 2.316977, 17, '151 bis Rue Cardinet', '#8ccaf7', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2nR_Xor7BaT04iU-yJG49qoTjR961aSAbHfCjXav0oYoZJyGLrr46VUCSEv0bEMa6W4UseJHDKYqw0Wp1pgmfOatZXLXEK3kBSvUTIyN_uwzHeecE_Reqcixfk75XF3UgDbPb1xNUtUetjGrqZBUm_0xkGm6mjdq3W8g0xsHv-j6LYl3UrmlECarcuvcnCpRbMFSbhUVGnEFh_BlCsggxUP9XUi7bd7NXz5agNwJrujBZPPDckiiHBwBWF-Srs1MY4QapU6NlBuCDP6wBczoEpEFpkx3TmVGQUG_aHcKxDYH5tf-og5_HJ99WqH_oQBnuW95FYE8Jqyhv4-NHW-BjmneQUCOJphNCSth2-9Mhti52eV7fo7Xy9PvLZwl_9pZfUxxOemgrpr4IgbSWrAJS5ECa9OitumvLeydTPM02jCP4&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 18, 0, '€', NULL, NULL, NULL, 0, 18, 50, '{"chill":21,"festif":4,"culturel":5}', '{}', '["restaurant","bistronomie"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":45,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":18,"budget_avg":18,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":18,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2nR_Xor7BaT04iU-yJG49qoTjR961aSAbHfCjXav0oYoZJyGLrr46VUCSEv0bEMa6W4UseJHDKYqw0Wp1pgmfOatZXLXEK3kBSvUTIyN_uwzHeecE_Reqcixfk75XF3UgDbPb1xNUtUetjGrqZBUm_0xkGm6mjdq3W8g0xsHv-j6LYl3UrmlECarcuvcnCpRbMFSbhUVGnEFh_BlCsggxUP9XUi7bd7NXz5agNwJrujBZPPDckiiHBwBWF-Srs1MY4QapU6NlBuCDP6wBczoEpEFpkx3TmVGQUG_aHcKxDYH5tf-og5_HJ99WqH_oQBnuW95FYE8Jqyhv4-NHW-BjmneQUCOJphNCSth2-9Mhti52eV7fo7Xy9PvLZwl_9pZfUxxOemgrpr4IgbSWrAJS5ECa9OitumvLeydTPM02jCP4&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Face au parc Martin Luther King, Coretta est l''une des pépites bistronomiques de l''ouest parisien. La chef Beatriz Gonzalez y propose une cuisine inventive, précise et magnifiquement présentée dans un cadre design baigné de lumière naturelle. Les mariages de saveurs sont audacieux et les produits d''une qualité irréprochable. C''est l''adresse idéale pour un déjeuner lumineux ou un dîner sophistiqué, où la technique culinaire se met au service d''une émotion gustative pure et moderne.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
