INSERT INTO places VALUES ('poi-217', 'Gyoza Bar', 'gyoza-bar-17', 'restaurant', 'japonais', 'chill', 48.876873, 2.336983, 17, '24 Rue Saint-Lazare', '#8ccaf7', 'pin', 1, 4.2, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN18Cqdn0b-prWuhunC0FgbOuEcVDkZOo935kD0D5qG8Mo5DSeaauINmu9ISVhtHCpA-tU4ltljh2Up6i7Hr3BgSJ-VJfb5KwzLtj5DGgcBYAjYfzCkQw0YDt1IP8pTSnm3EV49kvQo0rjsWoJTR7ZaYll0EXHjqpcxmc7m3WtinVEiIeiN3tilu6677vfGWCUjbqPdV0nnw3JPQp86YvCLGTYWs4oDRIr2gqNNksKkfym-NhVHXlcWnO6IwhuKCc_Rhhudk3ZZrSdpBa7Mat_DILJ4kLHUTgAEvvYY8O5g&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 16, 0, '€', NULL, NULL, NULL, 0, 16, 50, '{"chill":21,"festif":4,"culturel":5}', '{}', '["restaurant","japonais"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":20.5,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":16,"budget_avg":16,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":16,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN18Cqdn0b-prWuhunC0FgbOuEcVDkZOo935kD0D5qG8Mo5DSeaauINmu9ISVhtHCpA-tU4ltljh2Up6i7Hr3BgSJ-VJfb5KwzLtj5DGgcBYAjYfzCkQw0YDt1IP8pTSnm3EV49kvQo0rjsWoJTR7ZaYll0EXHjqpcxmc7m3WtinVEiIeiN3tilu6677vfGWCUjbqPdV0nnw3JPQp86YvCLGTYWs4oDRIr2gqNNksKkfym-NhVHXlcWnO6IwhuKCc_Rhhudk3ZZrSdpBa7Mat_DILJ4kLHUTgAEvvYY8O5g&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Japonais"],"drinks":[]}}', 'Le concept est simple et radical : d excellents gyozas et rien d autre (ou presque). Dans un décor minimaliste inspiré des comptoirs tokyoïtes, Gyoza Bar propose des raviolis japonais à la farce juteuse et à la pâte craquante, confectionnés sur place avec des produits de qualité. C''est rapide, c''est sain, c''est addictif et c est la garantie d un déjeuner ou d un dîner sur le pouce qui ne sacrifie jamais le goût à la vitesse. Une petite bulle japonaise épurée et efficace au centre du 17ème.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-217', 'Gyoza Bar', 'restaurant', 'japonais', '24 Rue Saint-Lazare', '', 'Le concept est simple et radical : d excellents gyozas et rien d autre (ou presque). Dans un décor minimaliste inspiré des comptoirs tokyoïtes, Gyoza Bar propose des raviolis japonais à la farce juteuse et à la pâte craquante, confectionnés sur place avec des produits de qualité. C''est rapide, c''est sain, c''est addictif et c est la garantie d un déjeuner ou d un dîner sur le pouce qui ne sacrifie jamais le goût à la vitesse. Une petite bulle japonaise épurée et efficace au centre du 17ème.');
