INSERT INTO places VALUES ('poi-208', 'Janine', 'janine-paris', 'restaurant', 'bistrot-moderne', 'chill', 48.883065, 2.317973, 17, '90 Rue des Dames', '#8ccaf7', 'pin', 1, 4.7, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2LXv2b_QJSjGeEIdgBcKtGLZEViCVbJLz8e4IiCR9e7btBU4Co015Eu4FAF579YM1ENGQBgOVJVCN4P5WIfTY0WtmxntNBASU-teTWdZLNxW5l4i4hr-gXE8J_VM2XQu2GdvEKsBTdZzSm1j3bHKfa7qLryVnQpoEtsRSAlHn791vD6ZCfjnAz4lF6jDd0aNxduxQHN-ZKccgYDDvxap9UZRPlOyDzYrt1IMA-1B3YyYUxpHMeT2eYPUSQuP8jVZkzlk0o5vN3JGtHbuk7feKS7r04tB5FOO5K7Q1RGywIjQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 28, 0, '€', NULL, NULL, NULL, 0, 28, 50, '{"chill":21,"festif":4,"culturel":5}', '{}', '["restaurant","bistrot-moderne"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":28,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":28,"budget_avg":28,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":28,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2LXv2b_QJSjGeEIdgBcKtGLZEViCVbJLz8e4IiCR9e7btBU4Co015Eu4FAF579YM1ENGQBgOVJVCN4P5WIfTY0WtmxntNBASU-teTWdZLNxW5l4i4hr-gXE8J_VM2XQu2GdvEKsBTdZzSm1j3bHKfa7qLryVnQpoEtsRSAlHn791vD6ZCfjnAz4lF6jDd0aNxduxQHN-ZKccgYDDvxap9UZRPlOyDzYrt1IMA-1B3YyYUxpHMeT2eYPUSQuP8jVZkzlk0o5vN3JGtHbuk7feKS7r04tB5FOO5K7Q1RGywIjQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Janine, c est le bistrot de coeur des Batignolles. Cuisine de marché inventive, produits sourcés chez les meilleurs artisans et carte des vins vivante (nature et vivants). On y déjeune d assiettes franches et on y dîne de compositions plus sophistiquées, toujours avec ce supplément d''âme qui fait les grandes adresses. Le service est adorable, l ambiance est celle d''une maison de potes, et l on ressort toujours d''ici avec le sourire et le ventre parfaitement heureux.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-208', 'Janine', 'restaurant', 'bistrot-moderne', '90 Rue des Dames', '', 'Janine, c est le bistrot de coeur des Batignolles. Cuisine de marché inventive, produits sourcés chez les meilleurs artisans et carte des vins vivante (nature et vivants). On y déjeune d assiettes franches et on y dîne de compositions plus sophistiquées, toujours avec ce supplément d''âme qui fait les grandes adresses. Le service est adorable, l ambiance est celle d''une maison de potes, et l on ressort toujours d''ici avec le sourire et le ventre parfaitement heureux.');
