INSERT INTO places VALUES ('poi-213', 'Le Bal', 'le-bal-paris', 'museum', 'espace-culturel', 'culturel', 48.885278, 2.327355, 17, '6 Imp. de la Défense', '#c499ff', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1dYALkmbH1Vr19ct8bF6ws3XnS1ObuUI97VoMDA3sbdwSv97fmE5COMatN2u2P5RdKNN7lULYrfENnbXTdW702P8szlZSDDUo8tT9yhv7bhDIgrwfELIgB3el7IdcPP3gcvfBApA6OPV5uVOFeoTQeYWn22VkpoaEHzPmaA-AoHviyCHFSPsHAmTygjaJKWTR3PcZNizVNjKzcTJUdtmgmwrcIGrQ866qA_OjX6swTaUeFI15-PqEp8JPdRQYH5q2Tnnn0ns5Pk7ttgJNFMzGQzMGFzQVb0FlxM_7nT5c6hg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":6,"festif":4,"culturel":24}', '{}', '["museum","espace-culturel"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":8,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":15,"type":"museum","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1dYALkmbH1Vr19ct8bF6ws3XnS1ObuUI97VoMDA3sbdwSv97fmE5COMatN2u2P5RdKNN7lULYrfENnbXTdW702P8szlZSDDUo8tT9yhv7bhDIgrwfELIgB3el7IdcPP3gcvfBApA6OPV5uVOFeoTQeYWn22VkpoaEHzPmaA-AoHviyCHFSPsHAmTygjaJKWTR3PcZNizVNjKzcTJUdtmgmwrcIGrQ866qA_OjX6swTaUeFI15-PqEp8JPdRQYH5q2Tnnn0ns5Pk7ttgJNFMzGQzMGFzQVb0FlxM_7nT5c6hg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'LE BAL est un carrefour culturel indépendant dédié à l''image documentaire sous toutes ses formes (photo, film, livre). Installé dans une ancienne salle de bal des années Folles au fond d une impasse, le lieu dégage une énergie créative et exigeante. On y vient pour découvrir des expositions pointues et souvent inédites, ou pour flâner dans l une des meilleures librairies photographiques de Paris. C''est un lieu vibrant, qui invite à la réflexion et à la contemplation de notre monde à travers l objectif.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-213', 'Le Bal', 'museum', 'espace-culturel', '6 Imp. de la Défense', '', 'LE BAL est un carrefour culturel indépendant dédié à l''image documentaire sous toutes ses formes (photo, film, livre). Installé dans une ancienne salle de bal des années Folles au fond d une impasse, le lieu dégage une énergie créative et exigeante. On y vient pour découvrir des expositions pointues et souvent inédites, ou pour flâner dans l une des meilleures librairies photographiques de Paris. C''est un lieu vibrant, qui invite à la réflexion et à la contemplation de notre monde à travers l objectif.');
