K3Z9KsoN5iNG_Q2-_KWV8bhaFzZ2OWQD8FYQ-oYyyrJua-wo4A1VP5mv6HpA8NQYmBbrm6z-8-ZOPbm-6qjIojEPydsfYV3ruqmu4m-Gq959e29dGuC-N9drgLj0P4GrIL0CQON6Bac0JIM98AxdfD-FX&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM"]', NULL, '{"insider_tip":"Art Brut et café librairie atypique au pied de Montmartre.","specials":{"cuisine":[],"drinks":[]}}', 'Au pied du Sacré-Cœur, dans une ancienne halle de marché style Baltard, se trouve ce musée dédié à l''art brut et à l''art singulier. C''est le musée des artistes marginaux, des fous et des visionnaires. L''ambiance y est unique, loin des musées classiques aseptisés. Le café sous la verrière, entouré de livres d''art et de gâteaux maison, est un lieu de détente génial après avoir grimpé les marches de Montmartre.', 'Art Brut et café librairie atypique au pied de Montmartre.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-062', 'Halle Saint-Pierre', 'museum', 'espace-culturel', '2 Rue Ronsard', '', 'Au pied du Sacré-Cœur, dans une ancienne halle de marché style Baltard, se trouve ce musée dédié à l''art brut et à l''art singulier. C''est le musée des artistes marginaux, des fous et des visionnaires. L''ambiance y est unique, loin des musées classiques aseptisés. Le café sous la verrière, entouré de livres d''art et de gâteaux maison, est un lieu de détente génial après avoir grimpé les marches de Montmartre.');
INSERT INTO places VALUES ('poi-126', 'La Recyclerie', 'la-recyclerie', 'restaurant', 'cantine-éco', 'festif', 48.897628, 2.344175, 18, '83 Bd Ornano', '#ffab60', 'pin', 1, 4.3, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2SJIWhcDxK-EF1tbwt5m6ScIUv3DPCQkveaear2KT9Plp_vrx_aVRkM2VBeuE1dbqA4gNps2FRFe96xpbsVW94BL81-Zgoh36XKe7p7sPkobUraKJClIGHNe5IHdaLiQHrO7vyEo5imWxnTY07N9WIO9W5TsYISwvY3pgFVmRutEqhqG0jUVJfKDj0wsxZKmfP1Lwo7zpafarjun-5L-T9V8H4GMNFKRzFBq8OXyC1WJerUb-wCDjwNBd2kMKSFnuYsdjmT1fdrpYDLTydl002D4oQoTkOTjg-zjRVXpUO5A&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 24, 0, '€', NULL, NULL, NULL, 0, 24, 50, '{"chill":6,"festif":22,"culturel":5}', '{}', '["restaurant","cantine-éco"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":25.8,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":24,"budget_avg":24,"type":"restaurant","menu_items":[],"_debug_manual_dish_price":24,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN2SJIWhcDxK-EF1tbwt5m6ScIUv3DPCQkveaear2KT9Plp_vrx_aVRkM2VBeuE1dbqA4gNps2FRFe96xpbsVW94BL81-Zgoh36XKe7p7sPkobUraKJClIGHNe5IHdaLiQHrO7vyEo5imWxnTY07N9WIO9W5TsYISwvY3pgFVmRutEqhqG0jUVJfKDj0wsxZKmfP1Lwo7zpafarjun-5L-T9V8H4GMNFKRzFBq8OXyC1WJerUb-wCDjwNBd2kMKSFnuYsdjmT1fdrpYDLTydl002D4oQoTkOTjg-zjRVXpUO5A&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Réservez le premier service pour une ambiance plus calme.","specials":{"cuisine":["Français"],"drinks":[]}}', 'Nichée dans une ancienne gare de la Petite Ceinture, la Recyclerie est un manifeste pour l''écologie urbaine. Entre sa ferme en pleine ville, son atelier de réparation et sa cantine bio, le lieu invite à repenser notre mode de consommation. La terrasse qui longe les rails est un spot unique à Paris, où l''on boit un café entouré de poules et de potagers aromatiques dans une atmosphère bucolique et militante.', 'Réservez le premier service pour une ambiance plus calme.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-126', 'La Recyclerie', 'restaurant', 'cantine-éco', '83 Bd Ornano', '', 'Nichée dans une ancienne gare de la Petite Ceinture, la Recyclerie est un manifeste pour l''écologie urbaine. Entre sa ferme en pleine ville, son atelier de réparation et sa cantine bio, le lieu invite à repenser notre mode de consommation. La terrasse qui longe les rails est un spot unique à Paris, où l''on boit un café entouré de poules et de potagers aromatiques dans une atmosphère bucolique et militante.');
INSERT INTO places VALUES ('poi-079', 'La Station — Gare des Mines', 'la-station', 'club', 'friche-culturelle', 'festif', 48.901224, 2.369937, 18, '29 Av. de la Prte d''Aubervilliers', '#ffab60', 'pin', 1, 4.4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0a35TXiMUVntUrWpiWx2pjdOPR3FBdmqtdvczlSK4KRdIk6SUAISmrLB3LI8pEOgdCvkF3p7SVPfSXP2tyY0a6avQXhUZPo-U_vlKASKqTWpNo5V0li4RO4SWIuE13-_hJPivEAjB4awQ442FdwjL9vd4eMTPJWYOuJ3QpB0Mb_jCVQNIO6lBRytv1Y1LmgIYR3j5hE-5Ia1pGNqUIJ78krCPobZUnp1T-asaRoDnYRRgSPnRM-1siVMYHQ6pyzL7QBxBwl-o-Z7YajsQYR6ZnLDn5r-UFKcFdDtnCtgeenQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 0, 0, '€', 6, NULL, NULL, 0, 0, 50, '{"chill":10,"festif":30,"culturel":5}', '{}', '["club","friche-culturelle"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":6,"is_free":false,"pint_price":6,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":0,"type":"club","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0a35TXiMUVntUrWpiWx2pjdOPR3FBdmqtdvczlSK4KRdIk6SUAISmrLB3LI8pEOgdCvkF3p7SVPfSXP2tyY0a6avQXhUZPo-U_vlKASKqTWpNo5V0li4RO4SWIuE13-_hJPivEAjB4awQ442FdwjL9vd4eMTPJWYOuJ3QpB0Mb_jCVQNIO6lBRytv1Y1LmgIYR3j5hE-5Ia1pGNqUIJ78krCPobZUnp1T-asaRoDnYRRgSPnRM-1siVMYHQ6pyzL7QBxBwl-o-Z7YajsQYR6ZnLDn5r-UFKcFdDtnCtgeenQ&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.","specials":{"cuisine":[],"drinks":[]}}', 'Née dans une ancienne gare de charbons à la lisière d''Aubervilliers, La Station est le projet fou du collectif MU. C''est une friche culturelle à l''état pur, où l''esthétique industrielle et bétonnée sert de décor à l''avant-garde musicale et artistique. Pendant les mois d''été, ses extérieurs se transforment en une immense aire de fête sauvage et inclusive. C''est un lieu qui refuse les codes du centre-ville pour offrir une liberté totale. On y vient pour l''imprévu, le son fort, et cette vibration brute qu''on ne trouve plus nulle part ailleurs.', 'Prévoyez vos bouchons d''oreilles, le sound system ne rigole pas.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-079', 'La Station — Gare des Mines', 'club', 'friche-culturelle', '29 Av. de la Prte d''Aubervilliers', '', 'Née dans une ancienne gare de charbons à la lisière d''Aubervilliers, La Station est le projet fou du collectif MU. C''est une friche culturelle à l''état pur, où l''esthétique industrielle et bétonnée sert de décor à l''avant-garde musicale et artistique. Pendant les mois d''été, ses extérieurs se transforment en une immense aire de fête sauvage et inclusive. C''est un lieu qui refuse les codes du centre-ville pour offrir une liberté totale. On y vient pour l''imprévu, le son fort, et cette vibration brute qu''on ne trouve plus nulle part ailleurs.');
INSERT INTO places VALUES ('poi-127', 'Le Hasard Ludique', 'le-hasard-ludique', 'bar', 'bar-concert', 'chill', 48.895697, 2.328596, 18, '128 Av. de Saint-Ouen', '#8ccaf7', 'pin', 1, 4.3, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3xGhAO_RMhLsX0js4dFHtsBQ4ZiwILcaPSMdh97BGWY3eoNrZj6CMZZid2-kblYC3fFTS7gP55LOZQSkpHuA5xVB6Kpf4zJXf21RixGkANkYHxDeNQ1UjXMZMtlodmeMNIIdlSuDHX--B2MEA0pCNBfoy18I_HgETH4Aa9Um2YbP8_9bbd046tqWjBQ0A4eyQ0yhFx7fUpF2_sLX-3d3nha809hr9yFcZL3Hlc7l_Y5026jV2N-2qmWarse1Rns-ukU6_d5P-pHSTtbPDkpTR8Hp6fCwgW6PvcuKe_b4zSIA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 7.5, 0, '€', 7.5, NULL, NULL, 0, 14, 50, '{"chill":22.5,"festif":5,"culturel":7}', '{}', '["bar","bar-concert"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":7.5,"cocktail_price":0,"coffee_price":0,"dish_price":14,"budget_avg":7.5,"type":"bar","menu_items":[],"_debug_manual_dish_price":14,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3xGhAO_RMhLsX0js4dFHtsBQ4ZiwILcaPSMdh97BGWY3eoNrZj6CMZZid2-kblYC3fFTS7gP55LOZQSkpHuA5xVB6Kpf4zJXf21RixGkANkYHxDeNQ1UjXMZMtlodmeMNIIdlSuDHX--B2MEA0pCNBfoy18I_HgETH4Aa9Um2YbP8_9bbd046tqWjBQ0A4eyQ0yhFx7fUpF2_sLX-3d3nha809hr9yFcZL3Hlc7l_Y5026jV2N-2qmWarse1Rns-ukU6_d5P-pHSTtbPDkpTR8Hp6fCwgW6PvcuKe_b4zSIA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Sur les rails de la Petite Ceinture du 18ème, le Hasard Ludique est un lieu culturel hybride et festif. Installé dans l''ancienne gare de l''Avenue de Saint-Ouen, il propose une salle de concert, un atelier créatif et une terrasse monumentale de 300m2 au ras des rails. Sa programmation pointue explore les musiques actuelles et les enjeux de société, le tout dans une ambiance toujours bienveillante et survoltée.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-127', 'Le Hasard Ludique', 'bar', 'bar-concert', '128 Av. de Saint-Ouen', '', 'Sur les rails de la Petite Ceinture du 18ème, le Hasard Ludique est un lieu culturel hybride et festif. Installé dans l''ancienne gare de l''Avenue de Saint-Ouen, il propose une salle de concert, un atelier créatif et une terrasse monumentale de 300m2 au ras des rails. Sa programmation pointue explore les musiques actuelles et les enjeux de société, le tout dans une ambiance toujours bienveillante et survoltée.');
INSERT INTO places VALUES ('poi-114', 'Le Très Particulier', 'le-tres-particulier', 'bar', 'speakeasy / jardin', 'culturel', 48.887906, 2.335317, 18, 'Hôtel Particulier Montmartre', '#c499ff', 'pin', 1, 4, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1laemGz2DYEkFo0GmoxQKNvkxI-ZNljssQ-Wde6YJy8hejG63VeayUtDxqIRSU1Ij9wWdyvUwVgHtiVQqTFTcx44HEhoznMiDHIF_kdKw9PwY-4W5RDainCX6-weCQLefe_JyCyDiQLt7QGjgy3YEopX_dsq7-W_uE936SPQd7quiC-EYa-SJOtzTzLKCq7BWTiPcQYJTZeLTMTfEN0H9K5FOS-8DQtng3VIoFUk-rTkxOc3VnKie62YbAW0Ev2xmEA_1tVnleZKw33jaJ4dGVIqlME967Gtgr7TU7PG4&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 0, 0, '€', NULL, 15, NULL, 0, 0, 50, '{"chill":5.2,"festif":5,"culturel":25}', '{}', '["bar","speakeasy / jardin"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":18,"is_free":false,"pint_price":0,"cocktail_price":15,"coffee_price":0,"dish_price":0,"budget_avg":0,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN1laemGz2DYEkFo0GmoxQKNvkxI-ZNljssQ-Wde6YJy8hejG63VeayUtDxqIRSU1Ij9wWdyvUwVgHtiVQqTFTcx44HEhoznMiDHIF_kdKw9PwY-4W5RDainCX6-weCQLefe_JyCyDiQLt7QGjgy3YEopX_dsq7-W_uE936SPQd7quiC-EYa-SJOtzTzLKCq7BWTiPcQYJTZeLTMTfEN0H9K5FOS-8DQtng3VIoFUk-rTkxOc3VnKie62YbAW0Ev2xmEA_1tVnleZKw33jaJ4dGVIqlME967Gtgr7TU7PG4&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Caché au sein de l''Hôtel Particulier Montmartre, accessible uniquement par un interphone, Le Très Particulier est le bar le plus exclusif de la butte. Son décor tropical et feutré se prolonge dans un jardin luxuriant où le temps semble s''arrêter. Les cocktails y sont sophistiqués et nommés d''après des films cultes.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-114', 'Le Très Particulier', 'bar', 'speakeasy / jardin', 'Hôtel Particulier Montmartre', '', 'Caché au sein de l''Hôtel Particulier Montmartre, accessible uniquement par un interphone, Le Très Particulier est le bar le plus exclusif de la butte. Son décor tropical et feutré se prolonge dans un jardin luxuriant où le temps semble s''arrêter. Les cocktails y sont sophistiqués et nommés d''après des films cultes.');
INSERT INTO places VALUES ('poi-123', 'Musée de Montmartre', 'musee-de-montmartre', 'museum', 'musée / vignobles', 'culturel', 48.887709, 2.340673, 18, '12 Rue Cortot', '#c499ff', 'pin', 1, 4.6, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3tyjT4JgL1blQa2E82DeKopfJxVM7HE-_VIYcEj34tbEtNWDzv-if6i4-hxg8Wi7jfOq7bAjricJCRRzg-f6H-NnZa3fS1VK0vhctE5mjHyFFU_9hgnSHNH6E7Wl8sTxyAiwXmpqzK1cY_rqAfZCXnMns4UhUNzrVFKlKgT5oGsWiVnQrnJoAwE2lgtsYcz825Ji_j-WVUAVZaUUMtOm1KdeXEIOuw65GiAVRf9s1MXPwKqYri9_PPWPSsWFdggUFq3ckAz-Y85o7XvMQXm56cWRIrOD6iRb7-uLo3qzCgBsETFk1QrVkTGl3XhzDMshbdnquovg3yfaSkNqeBD09cRaZodOWTfrkE6i1hAfJBvnnSxrBiMyVrsStSZVKNvFNMXSD5k4oyn5yHCC3QB9m7jIyTDKLqGENyjg4zDaUivA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 15, 0, '€', NULL, NULL, NULL, 0, 0, 50, '{"chill":9.2,"festif":4,"culturel":25}', '{}', '["museum","musée / vignobles"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":7,"is_free":false,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":15,"type":"museum","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3tyjT4JgL1blQa2E82DeKopfJxVM7HE-_VIYcEj34tbEtNWDzv-if6i4-hxg8Wi7jfOq7bAjricJCRRzg-f6H-NnZa3fS1VK0vhctE5mjHyFFU_9hgnSHNH6E7Wl8sTxyAiwXmpqzK1cY_rqAfZCXnMns4UhUNzrVFKlKgT5oGsWiVnQrnJoAwE2lgtsYcz825Ji_j-WVUAVZaUUMtOm1KdeXEIOuw65GiAVRf9s1MXPwKqYri9_PPWPSsWFdggUFq3ckAz-Y85o7XvMQXm56cWRIrOD6iRb7-uLo3qzCgBsETFk1QrVkTGl3XhzDMshbdnquovg3yfaSkNqeBD09cRaZodOWTfrkE6i1hAfJBvnnSxrBiMyVrsStSZVKNvFNMXSD5k4oyn5yHCC3QB9m7jIyTDKLqGENyjg4zDaUivA&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'Niché dans la plus vieille maison de la colline de Montmartre, ce musée est un enchantement total. Entre ses jardins inspirés des tableaux de Renoir et ses vues plongeantes sur les vignes du Clos Montmartre, le lieu respire l''esprit bohème de la Belle Époque. On y revit les heures de gloire du Bateau-Lavoir et d''Erik Satie dans une atmosphère bucolique et secrète, loin de l''agitation de la Place du Tertre.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-123', 'Musée de Montmartre', 'museum', 'musée / vignobles', '12 Rue Cortot', '', 'Niché dans la plus vieille maison de la colline de Montmartre, ce musée est un enchantement total. Entre ses jardins inspirés des tableaux de Renoir et ses vues plongeantes sur les vignes du Clos Montmartre, le lieu respire l''esprit bohème de la Belle Époque. On y revit les heures de gloire du Bateau-Lavoir et d''Erik Satie dans une atmosphère bucolique et secrète, loin de l''agitation de la Place du Tertre.');
