:"site","url":"https://www.larughetta.com/fr/","label":"SITE OFFICIEL"},"happy_hour":null}', '{"avg_budget":29,"is_free":false,"pint_price":0,"cocktail_price":0,"wine_glass":7,"coffee_price":2.5,"dish_price":14,"last_updated":"2026-03-05","menu_items":[{"category":"Antipasti","items":[{"name":"Insalata Tricolore","price":"4.00€"},{"name":"Tomates Mozzarella di Bufala","price":"7.00€"},{"name":"Antipasti Rughetta (Légumes marinés)","price":"8.00€"},{"name":"Carpaccio Rughetta","price":"8.00€"},{"name":"Parma Mozzarella","price":"8.00€"},{"name":"Assortiment de fromages italiens","price":"9.00€"},{"name":"Assortiment de charcuteries","price":"10.00€"}]},{"category":"Pâtes Fraîches","items":[{"name":"Spaghetti Bolognese","price":"13.00€"},{"name":"Tagliatelle Carbonara","price":"14.00€"},{"name":"Lasagne al forno","price":"14.00€"},{"name":"Tagliatelle ai funghi","price":"14.00€"},{"name":"Penne al Arrabiata","price":"14.00€"},{"name":"Tagliolini Rughetta","price":"15.00€"},{"name":"Gnocchi al pesto","price":"15.00€"},{"name":"Penne Siciliana","price":"16.00€"},{"name":"Raviolone crema e basilico","price":"16.00€"}]},{"category":"Pizzas","items":[{"name":"Margherita","price":"11.00€"},{"name":"Napoletana","price":"13.50€"},{"name":"Diavola","price":"14.50€"},{"name":"4 Fromages (Quattro formaggi)","price":"15.00€"}]},{"category":"Desserts","items":[{"name":"Mousse au chocolat maison","price":"7.00€"},{"name":"Panna Cotta (coulis fraise ou caramel)","price":"8.00€"},{"name":"Pizza au Nutella (pour 2)","price":"9.50€"},{"name":"Tiramisu maison","price":"9.50€"}]},{"category":"Glaces & Coupes","items":[{"name":"Gelato (3 boules, parfums au choix)","price":"7.00€"},{"name":"Sorbet (3 boules, parfums au choix)","price":"7.00€"},{"name":"Coupe Amarena","price":"8.00€"},{"name":"Coupe Biancaneve","price":"8.00€"},{"name":"Affogato al caffè","price":"8.00€"}]},{"category":"Boissons","items":[{"name":"Café Espresso","price":"2.50€"},{"name":"Bouteille d''eau (1/2L)","price":"3.50€"},{"name":"Bouteille d''eau (1L)","price":"5.00€"}]},{"category":"Vins & Bulles","items":[{"name":"Prosecco (Flûte)","price":"7.00€"},{"name":"Champagne Gauthier (Coupe)","price":"10.00€"},{"name":"Prosecco (Bouteille)","price":"39.00€"},{"name":"Champagne Gauthier (Bouteille)","price":"65.00€"},{"name":"Champagne Ruinart (Bouteille)","price":"95.00€"}]}],"budget_avg":14,"type":"restaurant","_debug_manual_dish_price":0,"_debug_median_dish_price":14}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photo_reference=ATCDNfXniz8orcHxxHoBtUzRxjWQhMPNGZEAiG3p43lJrs_9_aAWnQIYppYjmHbGAnbRP3DjIePxVDlthI1U3Of_y3oqVWVxGTi18hiEQqVBe-4nin3-h8XwROCe02STQA5Xc0GBGyml_-3P9HyxU30RdxcX8ALb5S1_sp8YYvJlt8vuww56nBy9FBoAPCb26uTAFqkeCzvfMJQH_DwhA4jv33hJZ3o5fhQsJfBYAjliyczA2BniJYGWvDM9zjDScu6h-enCSE90VzenwQmf1To1Hj6eaZMlTTXnUrp9tSyo4tyKXySKUjouD474h2-I4DLCwkcV0znycoNG6rnI-pJivdrPm6qCSxHTbpTfIJcUfKY3_GhIx9vb9GclRoPYPb0KasAYFtWE0ZPgb_Nk5gzja6rn9JoC52ghhcploJUXKRhjlbYlkWk_kNlVdD4D12IwYx2kCdRQq9hJQrfJ85Y1X_XPyY4vhIcruzLh6cUohA9EUKCX317ReAgUIO1XbSC5cM4uGGiQvCCZlMw_3Af80wzJqE4qa9MSIjDmeADH_hceJ8PwlKOgTJTEqd2k11dMZ_3H6cBS&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"• Les portions s''y avèrent particulièrement copieuses, prévoyez un appétit solide pour attaquer leurs assiettes de pâtes ou laissez-vous tenter par le doggy bag.\n• Au regard de son emplacement (et de l''affluence de touristes), ses prix très modérés en font une adresse locale exceptionnelle et véritablement préservée.\n• Les pizzas au format géant et particulièrement garnies tombent quasiment toutes hors de l''assiette. La ''4 fromages'' y est régulièrement plébiscitée.","specials":{"cuisine":["Pizza 4 fromages","Tagliolini Rughetta","Pizza au Nutella","Pizza Diavola"],"drinks":["Prosecco (7€)","Aperol Spritz"],"must_eat":"Cuisine italienne classique et très généreuse. L''endroit excelle tant par ses authentiques pizzas romaines à pâte fine comme la Diavola ou la 4 Formaggi, que par ses plats de pâtes fraîches copieusement servis comme les Tagliolini maison. Le Tiramisu et la spectaculaire Pizza au Nutella terminent de mettre tout le monde d''accord.","must_drink":"L''établissement dispose d''une très belle carte de vins italiens musclés. On peut également débuter son dîner par des valeurs sûres servies au comptoir comme le Prosecco (7€) ou de très bons Spritz."},"expert_catchline":"Trattoria authentique et généreuse, une bulle d''Italie abordable au coeur de la rue Lepic."}', 'Installée dans la très charmante rue Lepic, La Rughetta est une trattoria familiale où vit l''esprit authentique et chaleureux de l''Italie. Reconnue par une multitude d''habitués de Montmartre comme une adresse refuge incontournable au rapport qualité-prix bluffant, on y vient pour un service impeccable et bienveillant, typique de l''hospitalité italienne. Passé sa devanture accueillante, c''est un festival de parfums d''herbes aromatiques et de pâte à pain dorée qui attend les convives.', '• Les portions s''y avèrent particulièrement copieuses, prévoyez un appétit solide pour attaquer leurs assiettes de pâtes ou laissez-vous tenter par le doggy bag.
INSERT INTO places_fts VALUES ('poi-la-rughetta', 'La Rughetta', 'restaurant', 'italien pizzeria', '41 Rue Lepic', '', 'Installée dans la très charmante rue Lepic, La Rughetta est une trattoria familiale où vit l''esprit authentique et chaleureux de l''Italie. Reconnue par une multitude d''habitués de Montmartre comme une adresse refuge incontournable au rapport qualité-prix bluffant, on y vient pour un service impeccable et bienveillant, typique de l''hospitalité italienne. Passé sa devanture accueillante, c''est un festival de parfums d''herbes aromatiques et de pâte à pain dorée qui attend les convives.');
INSERT INTO places VALUES ('poi-089', 'Combat', 'combat', 'bar', 'mixology', 'festif', 48.873468, 2.382238, 19, '63 Rue de Belleville', '#ffab60', 'pin', 1, 0, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3wBzJ-9Hal5G6HR67xT9wMmKaQIGXW-AukHw9XngFvzSkAju7pHQYvg-xgQgy-sY5v_Zi8ie1xS56YlSkfzw7NrIv78V2GdZ8oXTfnyiJ6XkbBh_Y2MFmuTGbs4TgVSx1XOIx2f2-lkI5jTzNonYsshFyhqzhYwTbknyLdAk9nmVV1BasfGjeYUJcYa26RslkcLe026gMGMmqIuspU5jRmd41cO1TpyJQ3rfGPX0kzQqpXF9dqbt-oiN_clO3rsM-V9SwByyj7QBHgorC6oTePKK4YoUET1JH6mhlfWQ8pyg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 8, 0, '€', 8, NULL, NULL, 0, 0, 50, '{"chill":7,"festif":23,"culturel":8}', '{}', '["bar","mixology"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":8,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":8,"type":"bar","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN3wBzJ-9Hal5G6HR67xT9wMmKaQIGXW-AukHw9XngFvzSkAju7pHQYvg-xgQgy-sY5v_Zi8ie1xS56YlSkfzw7NrIv78V2GdZ8oXTfnyiJ6XkbBh_Y2MFmuTGbs4TgVSx1XOIx2f2-lkI5jTzNonYsshFyhqzhYwTbknyLdAk9nmVV1BasfGjeYUJcYa26RslkcLe026gMGMmqIuspU5jRmd41cO1TpyJQ3rfGPX0kzQqpXF9dqbt-oiN_clO3rsM-V9SwByyj7QBHgorC6oTePKK4YoUET1JH6mhlfWQ8pyg&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Combat, c''est l''essence de Belleville distillée dans un cocktail bar. Fondé par un collectif de femmes talentueuses issues des meilleures adresses parisiennes, le lieu tourne le dos aux speakeasies sombres pour offrir une salle lumineuse, minimaliste et végétale. On y vient pour une mixology de haut vol, sans snobisme, avec une carte qui fait la part belle aux agrumes, à l''amertume et aux produits de saison. L''ambiance y est celle d''un vrai bar de quartier où l''on se sent bien pour l''apéro sur le trottoir comme pour une soirée qui s''éternise à l''intérieur.', 'Arrivez tôt pour choper les tabourets du bar, c''est là que ça se passe.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-089', 'Combat', 'bar', 'mixology', '63 Rue de Belleville', '', 'Combat, c''est l''essence de Belleville distillée dans un cocktail bar. Fondé par un collectif de femmes talentueuses issues des meilleures adresses parisiennes, le lieu tourne le dos aux speakeasies sombres pour offrir une salle lumineuse, minimaliste et végétale. On y vient pour une mixology de haut vol, sans snobisme, avec une carte qui fait la part belle aux agrumes, à l''amertume et aux produits de saison. L''ambiance y est celle d''un vrai bar de quartier où l''on se sent bien pour l''apéro sur le trottoir comme pour une soirée qui s''éternise à l''intérieur.');
INSERT INTO places VALUES ('poi-120', 'Le Centquatre', 'le-centquatre', 'museum', 'espace multidisc.', 'festif', 48.889982, 2.371434, 19, '5 Rue Curial', '#ffab60', 'pin', 1, 4.5, 0, 'https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0ekJAJtK1PACF3uLhm5Xmxv9txjZQcBGBe1xETqyuMAtBcpBMb4dHQAoMynmHIlPNkElJltYrfWtjja8YeyIrHCUCuLHxdxqPscg_HiLl66A5kWqX02U8UcIIrx9HAxed8Jqw3bkkO36MFUBS616LHR8iVoMHmxMvDU56laxZtXJW76qj4uUoZD9MNEaEWoqOsH6AsdpIsp59n1YOYkL8Ggj3qKRk4iYPCnQ1JNE4JLGWbPlrXp_ApTK8w2ovn8GLvqlHgZQtPkckuLedgloJ0HhY_DDcvpZu5gjLzhE8ScOhzt7a3ct7Z8EIa5BvGcOLTM7DiCRQ38zqCT6BT_VTRWVINKTSBmvfYBs0rkETO3wVBHItH8RsFDWoLfbSuQpxvjz0Wyi0Z9P0DWl70RLQaDHi5IiG5hjTjeikAdvw5x6Hd&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM', NULL, 15, 0, '€', 6, NULL, NULL, 0, 0, 50, '{"chill":7.2,"festif":24.3,"culturel":8}', '{}', '["museum","espace multidisc."]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"index_price":15,"avg_budget":15,"is_free":false,"pint_price":6,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":15,"type":"museum","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"https://maps.googleapis.com/maps/api/place/photo?maxwidth=1600&photoreference=AcnlKN0ekJAJtK1PACF3uLhm5Xmxv9txjZQcBGBe1xETqyuMAtBcpBMb4dHQAoMynmHIlPNkElJltYrfWtjja8YeyIrHCUCuLHxdxqPscg_HiLl66A5kWqX02U8UcIIrx9HAxed8Jqw3bkkO36MFUBS616LHR8iVoMHmxMvDU56laxZtXJW76qj4uUoZD9MNEaEWoqOsH6AsdpIsp59n1YOYkL8Ggj3qKRk4iYPCnQ1JNE4JLGWbPlrXp_ApTK8w2ovn8GLvqlHgZQtPkckuLedgloJ0HhY_DDcvpZu5gjLzhE8ScOhzt7a3ct7Z8EIa5BvGcOLTM7DiCRQ38zqCT6BT_VTRWVINKTSBmvfYBs0rkETO3wVBHItH8RsFDWoLfbSuQpxvjz0Wyi0Z9P0DWl70RLQaDHi5IiG5hjTjeikAdvw5x6Hd&key=AIzaSyDpkuHPvH-X8hZrLrpZbyC2Hi39iAfrLKM","gallery":[]}', '[]', NULL, '{"insider_tip":"L''entrée est gratuite tous les premiers dimanches du mois.","specials":{"cuisine":[],"drinks":[]}}', 'Installé dans les anciens pompes funèbres de Paris, le CENTQUATRE est devenu l''un des centres culturels les plus vibrants de la capitale. Sous ses grandes halles de verre et de fer, on croise des danseurs de hip-hop s''entraînant devant les miroirs, des circassiens et des expositions d''art contemporain monumentales. C''est un lieu hybride, populaire et exigeant, qui respire la vie et la création à chaque mètre carré.', 'L''entrée est gratuite tous les premiers dimanches du mois.', 'À proximité', '[]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-120', 'Le Centquatre', 'museum', 'espace multidisc.', '5 Rue Curial', '', 'Installé dans les anciens pompes funèbres de Paris, le CENTQUATRE est devenu l''un des centres culturels les plus vibrants de la capitale. Sous ses grandes halles de verre et de fer, on croise des danseurs de hip-hop s''entraînant devant les miroirs, des circassiens et des expositions d''art contemporain monumentales. C''est un lieu hybride, populaire et exigeant, qui respire la vie et la création à chaque mètre carré.');
INSERT INTO places VALUES ('poi-007', 'Rosa Bonheur Buttes-Chaumont', 'rosa-bonheur-buttes', 'bar', 'guinguette', 'festif', 48.879936, 2.386241, 19, 'Parc des Buttes-Chaumont', '#ffab60', 'pin', 1, 4.2, 0, 'https://upload.wikimedia.org/wikipedia/commons/4/4e/Guinguette_Rosa_Bonheur_-_Parc_des_Buttes-Chaumont.jpg', NULL, 8.5, 0, '€', 8.5, NULL, NULL, 0, 14, 50, '{"chill":8,"festif":24.5,"culturel":6}', '{}', '["bar","guinguette"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":2,"is_free":false,"pint_price":8.5,"cocktail_price":0,"coffee_price":0,"dish_price":14,"budget_avg":8.5,"type":"bar","menu_items":[],"_debug_manual_dish_price":14,"_debug_median_dish_price":null}', '{"hero":"https://upload.wikimedia.org/wikipedia/commons/4/4e/Guinguette_Rosa_Bonheur_-_Parc_des_Buttes-Chaumont.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez avant 19h pour éviter la queue monstre. Ambiance imbattable.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Une guinguette moderne au cœur du parc le plus romantique de Paris. Rosa Bonheur a réinvesti un ancien pavillon du XIXe siècle pour en faire un lieu de fête libre et tolérant, où l''on ''boit du rosé et on mange du jambon'' sans chichis. Dès 18h, la terrasse se remplit, la musique monte, et tout le monde danse, des familles aux fêtards queer, dans une joyeuse mixité. C''est l''endroit parfait pour voir le soleil se coucher sur Paris avant de se déhancher sur des tubes disco jusqu''à la fermeture du parc.', 'Arrivez avant 19h pour éviter la queue monstre. Ambiance imbattable.', 'Botzaris', '[7]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-007', 'Rosa Bonheur Buttes-Chaumont', 'bar', 'guinguette', 'Parc des Buttes-Chaumont', '', 'Une guinguette moderne au cœur du parc le plus romantique de Paris. Rosa Bonheur a réinvesti un ancien pavillon du XIXe siècle pour en faire un lieu de fête libre et tolérant, où l''on ''boit du rosé et on mange du jambon'' sans chichis. Dès 18h, la terrasse se remplit, la musique monte, et tout le monde danse, des familles aux fêtards queer, dans une joyeuse mixité. C''est l''endroit parfait pour voir le soleil se coucher sur Paris avant de se déhancher sur des tubes disco jusqu''à la fermeture du parc.');
INSERT INTO places VALUES ('poi-024', 'Parc des Buttes-Chaumont', 'buttes-chaumont', 'parc', 'parc-romantique', 'chill', 48.88095, 2.382761, 19, '1 Rue Botzaris', '#8ccaf7', 'pin', 1, 4.6, 0, '/images/buttes-chaumont.jpg', NULL, 0, 1, '€', 0, 0, 0, 0, 0, 50, '{"chill":24.5,"festif":5,"culturel":7}', '{}', '["parc","parc-romantique"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":2,"is_free":true,"pint_price":0,"cocktail_price":0,"coffee_price":0,"dish_price":0,"budget_avg":0,"type":"parc","menu_items":[],"_debug_manual_dish_price":0,"_debug_median_dish_price":null}', '{"hero":"/images/buttes-chaumont.jpg","gallery":[]}', '[]', NULL, '{"insider_tip":"Prépare tes mollets, ça grimpe sec !","specials":{"cuisine":[],"drinks":[]}}', 'Le parc le plus escarpé, romantique et ''montagnard'' de Paris. Construit sous Napoléon III sur d''anciennes carrières de gypse, c''est un chef-d''œuvre de paysage artificiel : fausses falaises, grotte avec cascade, pont suspendu par Gustave Eiffel et le fameux Temple de la Sibylle perché sur son piton rocheux qui offre une vue sublime sur Montmartre. C''est le spot préféré des parisiens pour les pique-niques en pente, les apéros qui s''éternisent et les joggings cardio (ça grimpe !).', 'Prépare tes mollets, ça grimpe sec !', 'Buttes Chaumont', '[7]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-024', 'Parc des Buttes-Chaumont', 'parc', 'parc-romantique', '1 Rue Botzaris', '', 'Le parc le plus escarpé, romantique et ''montagnard'' de Paris. Construit sous Napoléon III sur d''anciennes carrières de gypse, c''est un chef-d''œuvre de paysage artificiel : fausses falaises, grotte avec cascade, pont suspendu par Gustave Eiffel et le fameux Temple de la Sibylle perché sur son piton rocheux qui offre une vue sublime sur Montmartre. C''est le spot préféré des parisiens pour les pique-niques en pente, les apéros qui s''éternisent et les joggings cardio (ça grimpe !).');
INSERT INTO places VALUES ('poi-009', 'Le Pavillon Puebla', 'pavillon-puebla', 'bar', 'guinguette', 'chill', 48.87724, 2.379299, 19, 'Parc des Buttes-Chaumont', '#8ccaf7', 'pin', 1, 4, 0, 'https://images.unsplash.com/photo-1467003909585-2f8a7270028d?auto=format&fit=crop&w=800&q=80', NULL, 5, 0, '€', 5, NULL, NULL, 0, 18, 50, '{"chill":23.8,"festif":7,"culturel":7.2}', '{}', '["bar","guinguette"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":15,"is_free":false,"pint_price":5,"cocktail_price":0,"coffee_price":0,"dish_price":18,"budget_avg":5,"type":"bar","menu_items":[],"_debug_manual_dish_price":18,"_debug_median_dish_price":null}', '{"hero":"https://images.unsplash.com/photo-1467003909585-2f8a7270028d?auto=format&fit=crop&w=800&q=80","gallery":[]}', '[]', NULL, '{"insider_tip":"Le spot le plus romantique caché dans les arbres. Pizzas à partager absolument.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Cachée dans le parc des Buttes-Chaumont, cette grande maison de maître du XIXème siècle recouverte de lierre est un secret bien gardé des habitants de l''Est parisien. Accessible par un escalier de pierre discret, le Pavillon Puebla offre deux terrasses suspendues dans les arbres et un intérieur cosy décoré de tapis persans et de fauteuils en velours. On s''y sent comme dans une maison de campagne. C''est le spot idéal pour un apéro bucolique loin du bitume, avec des cocktails au gin et une ambiance qui devient festive et dansante une fois la nuit tombée. Un îlot de verdure féerique et décontracté.', 'Le spot le plus romantique caché dans les arbres. Pizzas à partager absolument.', 'Buttes Chaumont', '[7]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-009', 'Le Pavillon Puebla', 'bar', 'guinguette', 'Parc des Buttes-Chaumont', '', 'Cachée dans le parc des Buttes-Chaumont, cette grande maison de maître du XIXème siècle recouverte de lierre est un secret bien gardé des habitants de l''Est parisien. Accessible par un escalier de pierre discret, le Pavillon Puebla offre deux terrasses suspendues dans les arbres et un intérieur cosy décoré de tapis persans et de fauteuils en velours. On s''y sent comme dans une maison de campagne. C''est le spot idéal pour un apéro bucolique loin du bitume, avec des cocktails au gin et une ambiance qui devient festive et dansante une fois la nuit tombée. Un îlot de verdure féerique et décontracté.');
INSERT INTO places VALUES ('poi-073', 'Paname Brewing Company', 'paname-brewing-company', 'bar', 'craft beer', 'festif', 48.887832, 2.37879, 19, '41 bis Quai de la Loire', '#ffab60', 'pin', 1, 4.4, 0, 'https://images.unsplash.com/photo-1514933651103-005eec06c04b?auto=format&fit=crop&q=80&w=1000', NULL, 8.5, 0, '€', 8.5, NULL, NULL, 0, 16.5, 50, '{"chill":12,"festif":28,"culturel":8}', '{}', '["bar","craft beer"]', '{"standard":"Voir sur place","display":"Voir sur place","detailed":"","is_open_now":false}', '{"reservation_policy":null,"accessibility":false,"wifi":false,"opening_hours_raw":"","action_type":"site","action_url":"","terrace":false,"happy_hour":null}', '{"avg_budget":25,"is_free":false,"pint_price":8.5,"cocktail_price":0,"coffee_price":0,"dish_price":16.5,"budget_avg":8.5,"type":"bar","menu_items":[],"_debug_manual_dish_price":16.5,"_debug_median_dish_price":null}', '{"hero":"https://images.unsplash.com/photo-1514933651103-005eec06c04b?auto=format&fit=crop&q=80&w=1000","gallery":[]}', '[]', NULL, '{"insider_tip":"Arrivez tôt pour choper les tabourets du bar ou visez le ponton flottant pour l''expérience totale.","specials":{"cuisine":[],"drinks":["Cocktail"]}}', 'Ancien entrepôt de grains de la Villette transformé en micro-brasserie artisanale. Le lieu cultive un esprit industriel balnéaire unique, notamment grâce à son ponton flottant suspendu au-dessus du Canal de l''Ourcq, idéal pour voir le soleil se coucher sur le bassin.', 'Arrivez tôt pour choper les tabourets du bar ou visez le ponton flottant pour l''expérience totale.', 'Jaurès / Laumière', '[2,5,7]', '[]', NULL);
INSERT INTO places_fts VALUES ('poi-073', 'Paname Brewing Company', 'bar', 'craft beer', '41 bis Quai de la Loire', '', 'Ancien entrepôt de grains de la Villette transformé en micro-brasserie artisanale. Le lieu cultive un esprit industriel balnéaire unique, notamment grâce à son ponton flottant suspendu au-dessus du Canal de l''Ourcq, idéal pour voir le soleil se coucher sur le bassin.');
